let token=localStorage.getItem('cnine_admin_token')||sessionStorage.getItem('cnine_admin_token')||'';
let state={userVerificationFilter:'ALL',cardManageView:'MEMBERS',cardMemberFilter:'',cards:[],members:[],users:[],role:'',admin:null,view:'dashboard',rateData:null,packData:null,selectedPackId:'basic',breakthroughData:null,breakthroughGrade:'SR',battleData:null,dirtyCardIds:new Set(),raidData:null,tierData:null};
const RARITIES=['FUR','LIMITED','MA','SSR','UR','HR','SR','R','U','C'];
const $=s=>document.querySelector(s),esc=s=>String(s??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));
const img=v=>/^https?:\/\//i.test(v)?v:'/'+String(v||'').replace(/^\//,'');
async function api(path,opt={}){
  const r=await fetch('../api/'+path,{...opt,headers:{'content-type':'application/json','authorization':'Bearer '+token,...(opt.headers||{})},cache:'no-store'});
  const text=await r.text();let d={};
  try{d=text?JSON.parse(text):{}}catch{const e=Error('API 경로 또는 Cloudflare Functions 연결을 확인해주세요.');e.status=r.status;throw e}
  if(!r.ok){const e=Error(d.error||'요청 실패');e.status=r.status;e.code=d.code;throw e}
  return d;
}
function setBusy(btn,busy,text='처리 중...'){if(!btn)return;btn.disabled=busy;if(!btn.dataset.label)btn.dataset.label=btn.textContent;btn.textContent=busy?text:btn.dataset.label}
async function login(){const btn=$('#loginBtn'),key=$('#key').value.trim();if(!key)return alert('관리자 개인키를 입력하세요.');setBusy(btn,true,'로그인 확인 중...');try{const d=await api('admin/auth/login',{method:'POST',body:JSON.stringify({privateKey:key})}),role=String(d.user?.role||'').toUpperCase();if(!['OWNER','ADMIN','CARD_MANAGER','EVENT_MANAGER','SUPPORT'].includes(role))throw Error('관리자 권한이 없는 계정입니다.');if(!d.token)throw Error('관리자 로그인 정보를 발급받지 못했습니다.');token=d.token;localStorage.setItem('cnine_admin_token',token);sessionStorage.setItem('cnine_admin_token',token);$('#key').value='';await boot()}catch(e){alert(e.message||'관리자 로그인 중 오류가 발생했습니다.')}finally{setBusy(btn,false)}}
function setAuthScreen(isAuthenticated){document.body.classList.toggle('auth-active',isAuthenticated);document.body.classList.toggle('auth-guest',!isAuthenticated);$('#login').hidden=isAuthenticated;$('#cms').hidden=!isAuthenticated}
async function boot(){
  try{
    const d=await api('admin/dashboard');
    state.role=d.role;
    state.admin=d.admin||{nickname:'관리자',role:d.role};
    setAuthScreen(true);
    renderIdentity();
    show('dashboard',d);
  }catch(e){
    setAuthScreen(false);
    if(e.status===401||e.status===403){
      alert('관리자 인증 확인에 실패했습니다. 저장된 로그인 정보는 삭제하지 않았습니다.\n페이지를 새로고침하거나 다시 로그인해주세요.');
    }else{
      alert(`CMS 정보를 불러오지 못했습니다. 관리자 권한은 유지됩니다.\n${e.message}`);
    }
  }
}
async function loadWagoAdmin(){const d=await api('admin/wago-verifications');$('#wagoVerifyEnabled').value=d.settings.enabled===false?'0':'1';$('#wagoCodeMinutes').value=d.settings.codeMinutes||20;$('#wagoPostUrl').value=d.settings.postUrl||'';const box=$('#wagoVerificationList');const label={PENDING:'댓글 대기',REVIEW:'승인 검토',VERIFIED:'인증 완료',REJECTED:'거절'};box.innerHTML=d.verifications.length?d.verifications.map(v=>`<div class="row"><span><b>${esc(v.game_nickname)}</b><small>${esc(v.wago_nickname)} · #${esc(v.wago_member_no)}</small></span><span>${label[v.status]||esc(v.status)}<small>${fmt(v.issued_at)}</small></span><span><code>${esc(v.verification_code)}</code><small>${esc(v.review_note||'')}</small></span><span>${v.status!=='VERIFIED'?`<button data-wago-action="APPROVE" data-id="${v.id}">승인</button><button data-wago-action="REJECT" data-id="${v.id}" class="danger">거절</button>`:`<button data-wago-action="RESET" data-id="${v.id}" class="ghost">재인증</button>`}</span></div>`).join(''):'<div class="muted">인증 요청이 없습니다.</div>';box.querySelectorAll('[data-wago-action]').forEach(b=>b.onclick=()=>reviewWago(Number(b.dataset.id),b.dataset.wagoAction))}
async function saveWagoSettings(){await api('admin/wago-verifications',{method:'PATCH',body:JSON.stringify({settings:{enabled:$('#wagoVerifyEnabled').value==='1',codeMinutes:Number($('#wagoCodeMinutes').value),postUrl:$('#wagoPostUrl').value.trim()}})});alert('와고 인증 설정이 저장되었습니다.');loadWagoAdmin()}
async function reviewWago(id,action){const note=action==='REJECT'?prompt('거절 사유','인증 정보 불일치'):(action==='APPROVE'?prompt('승인 메모','댓글 및 회원번호 확인'):'재인증 요청');if(note===null)return;await api('admin/wago-verifications',{method:'PATCH',body:JSON.stringify({id,action,note})});await loadWagoAdmin()}

async function loadDailyQuestAdmin(){
  const d=await api('admin/daily-quests'),s=d.settings||{},stats=d.stats||{},users=d.users||[],logs=d.claims||[];
  $('#dqEnabled').value=s.enabled===false?'0':'1';
  $('#dqPostEnabled').value=s.postEnabled===false?'0':'1';
  $('#dqRequiredPosts').value=Number(s.requiredPosts||15);
  $('#dqPostRewardCoin').value=Number(s.postRewardCoin||s.rewardCoin||1200);
  $('#dqPostMaxPages').value=Number(s.maxPages||10);
  $('#dqCooldown').value=Number(s.checkCooldownSeconds||20);
  $('#dqAdminTestAllowed').value=s.adminTestAllowed===false?'0':'1';
  $('#dailyQuestAdminStats').innerHTML=[['오늘 참여자',stats.participants||0,'진행 기록 기준'],['게시글 완료',stats.postCompleted||0,`기준 ${Number(s.requiredPosts||15)}개`],['보상 수령',stats.postClaims||0,`${Number(stats.postCoins||0).toLocaleString()}코인 지급`]].map(x=>`<div class="stat"><small>${x[0]}</small><b>${Number(x[1]).toLocaleString()}</b><span>${x[2]}</span></div>`).join('');
  $('#dailyQuestAdminUsers').innerHTML=users.length?users.map(u=>`<article class="dailyQuestUserRow"><div><b>${esc(u.nickname)}</b><small>${esc(u.wago_nickname||'미인증')} · ${esc(u.role||'USER')}</small></div><span>글 <b>${Number(u.post_count||0)} / ${Number(s.requiredPosts||15)}</b>${u.post_claimed_at?'<em class="done">수령</em>':'<em>미수령</em>'}</span><small>${fmt(u.last_checked_at)}</small></article>`).join(''):'<div class="muted">오늘 진행 기록이 없습니다.</div>';
  $('#dailyQuestClaimLogs').innerHTML=logs.length?`<div class="tr head"><span>유저</span><span>퀘스트</span><span>보상</span><span>수령시간</span></div>${logs.map(x=>`<div class="tr"><span>${esc(x.nickname)}</span><span>게시글 ${Number(s.requiredPosts||15)}개</span><span>${Number(x.reward_coin||0).toLocaleString()}코인</span><span>${fmt(x.claimed_at)}</span></div>`).join('')}`:'<div class="muted">보상 지급 기록이 없습니다.</div>';
}
async function saveDailyQuestAdmin(){
  const settings={enabled:$('#dqEnabled').value==='1',postEnabled:$('#dqPostEnabled').value==='1',requiredPosts:Number($('#dqRequiredPosts').value),postRewardCoin:Number($('#dqPostRewardCoin').value),rewardCoin:Number($('#dqPostRewardCoin').value),maxPages:Number($('#dqPostMaxPages').value),checkCooldownSeconds:Number($('#dqCooldown').value),adminTestAllowed:$('#dqAdminTestAllowed').value==='1',boardUrl:'https://ygosu.com/board/soop'};
  await api('admin/daily-quests',{method:'PATCH',body:JSON.stringify({settings})});alert('일일퀘스트 설정이 저장되었습니다.');await loadDailyQuestAdmin();
}
async function sendVerifiedCoinMessages(){const amount=Number($('#verifiedCoinReward').value),includeOwner=Boolean($('#verifiedCoinIncludeOwner')?.checked),includeAdmin=Boolean($('#verifiedCoinIncludeAdmin')?.checked);if(!amount||amount<1)return alert('지급 코인을 입력하세요.');const extra=[includeOwner?'OWNER':'',includeAdmin?'ADMIN':''].filter(Boolean);if(!confirm(`2단계 인증 완료 유저에게 ${amount.toLocaleString()}코인 메시지를 발송할까요?${extra.length?`\n포함: ${extra.join(', ')}`:'\nOWNER·ADMIN 제외'}`))return;const d=await api('admin/verified-coin-message-send',{method:'POST',body:JSON.stringify({rewardCoin:amount,title:$('#verifiedCoinTitle').value,body:$('#verifiedCoinBody').value,includeOwner,includeAdmin})});alert(`${d.sent}명에게 ${Number(d.rewardCoin).toLocaleString()}코인 수령 메시지를 발송했습니다.\n일반 ${d.sentUsers||0}명 · OWNER ${d.sentOwners||0}명 · ADMIN ${d.sentAdmins||0}명`)}
async function sendVerifiedCoupons(){const includeOwner=Boolean($('#verifiedCouponIncludeOwner')?.checked),includeAdmin=Boolean($('#verifiedCouponIncludeAdmin')?.checked),extra=[includeOwner?'OWNER':'',includeAdmin?'ADMIN':''].filter(Boolean);if(!confirm(`와고 인증 완료 유저에게 개인 쿠폰을 발송할까요?${extra.length?`\n포함: ${extra.join(', ')}`:'\nOWNER·ADMIN 제외'}`))return;const d=await api('admin/verified-coupon-send',{method:'POST',body:JSON.stringify({campaignName:$('#verifiedCampaign').value,rewardCoin:Number($('#verifiedRewardCoin').value),title:$('#verifiedMessageTitle').value,body:$('#verifiedMessageBody').value,endsAt:toSql($('#verifiedCouponEnd').value),includeOwner,includeAdmin})});alert(`${d.sent}명에게 ${Number(d.rewardCoin).toLocaleString()}코인 쿠폰을 발송했습니다.\n일반 ${d.sentUsers||0}명 · OWNER ${d.sentOwners||0}명 · ADMIN ${d.sentAdmins||0}명`)}

function renderIdentity(){const a=state.admin||{};$('#roleBadge').textContent=state.role;$('#adminName').textContent=a.nickname||'관리자';$('#welcomeName').textContent=a.nickname||'관리자';$('#adminLoginAt').textContent='로그인됨 · '+fmt(a.last_login_at||new Date().toISOString());const raidNav=document.querySelector('#nav button[data-view="raid"]');if(raidNav)raidNav.hidden=state.role!=='OWNER'}
function show(view,prefetched){if(view==='raid'&&state.role!=='OWNER'){alert('레이드 관리는 OWNER만 사용할 수 있습니다.');view='dashboard';prefetched=null}state.view=view;document.querySelectorAll('.view').forEach(x=>x.hidden=x.id!==`view-${view}`);document.querySelectorAll('#nav button').forEach(x=>x.classList.toggle('active',x.dataset.view===view));$('#pageTitle').textContent={dashboard:'대시보드',pending:'신규 카드 대기함',cards:'카드관리',battle:'전투관리',ultimate:'궁극기 관리',raid:'레이드 관리',users:'유저관리',coupons:'쿠폰관리',wago:'와고 인증·메시지',logs:'관리자로그',tiers:'티어관리',mineral:'미네랄 교환',dailyquests:'일일퀘스트',settings:'설정'}[view];({dashboard:loadDashboard,pending:loadPending,cards:loadCards,battle:loadBattleAdmin,ultimate:loadUltimateAdmin,raid:loadRaidAdmin,tiers:loadTierAdmin,users:loadUsers,coupons:loadCoupons,wago:loadWagoAdmin,dailyquests:loadDailyQuestAdmin,logs:loadLogs,mineral:loadMineralAdmin,settings:loadSettings}[view])(prefetched).catch(e=>alert(e.message))}
async function loadDashboard(d){d=d||await api('admin/dashboard');state.role=d.role;state.admin=d.admin||state.admin;renderIdentity();const s=d.stats;const items=[['전체 유저',s.users,'누적 가입자'],['오늘 가입',s.usersToday||0,'오늘 신규 계정'],['24시간 카드뽑기',s.draws24h,'최근 24시간'],['활성 카드',s.cards,'현재 노출 카드'],['전체 보유 코인',Number(s.totalCoin).toLocaleString(),'모든 유저 합계'],['이용정지',s.banned,'현재 차단 계정'],['UR 보유',s.urOwned||0,'전체 보유 수량'],['SSR 보유',s.ssrOwned||0,'전체 보유 수량'],['활성 쿠폰',s.coupons,'현재 사용 가능']];$('#stats').innerHTML=items.map(x=>`<div class="stat"><small>${x[0]}</small><b>${x[1]}</b><em>${x[2]}</em></div>`).join('')}
async function loadCards(){state.dirtyCardIds.clear();updateBulkCardSaveState();const [d,r,packs]=await Promise.all([api('admin/cards'),api('admin/card-rates'),api('admin/card-packs')]);state.cards=d.cards;state.members=d.members;state.rateData=r;state.packData=packs;if(!packs.packs.some(p=>p.id===state.selectedPackId))state.selectedPackId=packs.packs[0]?.id||'basic';updatePendingCount();$('#memberId').innerHTML=d.members.map(m=>`<option value="${m.id}">${esc(m.name)}</option>`).join('');renderPackManager();renderRateManager();renderCards()}

function cardStatusLabel(c){return c.cardStatus==='RETIRE_PENDING'?'삭제 대기':c.cardStatus==='RETIRED'?'퇴사 완료':c.is_active?'활성':'비활성'}
function cardStatusClass(c){return c.cardStatus==='RETIRE_PENDING'?'pending':c.cardStatus==='RETIRED'?'retired':c.is_active?'active':'inactive'}
function cardEditorMarkup(c){return `<article class="card adminCard" data-id="${c.id}"><div class="cardThumbWrap"><img src="${esc(img(c.image))}" style="object-position:${c.focusX}% ${c.focusY}%"><span class="cardStateBadge ${cardStatusClass(c)}">${cardStatusLabel(c)}</span><span class="gradeBadge grade-${esc(c.grade)}">${esc(c.grade)}</span></div><div class="body"><div class="meta">${esc(c.name)} · ID ${c.id}</div><input class="title" value="${esc(c.title)}"><div class="row"><select class="member">${state.members.map(m=>`<option value="${m.id}" ${m.id==c.memberId?'selected':''}>${esc(m.name)}</option>`).join('')}</select><select class="rarity">${RARITIES.map(r=>`<option ${r===c.grade?'selected':''}>${r}</option>`).join('')}</select></div><input class="image" value="${esc(c.image)}"><div class="row"><input class="fx" type="number" value="${c.focusX}" title="가로 위치"><input class="fy" type="number" value="${c.focusY}" title="세로 위치"></div>${['SSR','MA','LIMITED','FUR'].includes(c.grade)?`<label class="field cardPowerTypeField"><span>전투력 유형</span><select class="powerType" ${c.grade==='FUR'?'disabled':''}>${c.grade==='FUR'?'<option value="FIXED" selected>기본형 · 3,200</option>':`<option value="" ${!c.powerType?'selected':''}>미설정 · 기존 등급값 유지</option><option value="NORMAL" ${c.powerType==='NORMAL'?'selected':''}>일반형</option><option value="HIGH" ${c.powerType==='HIGH'?'selected':''}>상급형</option><option value="TOP" ${c.powerType==='TOP'?'selected':''}>최상급형</option>`}</select><small class="powerPreview">${c.basePower?`기본 전투력 ${Number(c.basePower).toLocaleString()}`:'유형을 선택하면 자동 적용'}</small></label>`:''}<div class="row"><label class="field"><span>개별 가중치</span><input class="weight" type="number" min="0" step="0.01" value="${c.drawWeight??1}"></label><label class="field"><span>전체 한정 수량</span><input class="limit" type="number" min="0" placeholder="무제한" value="${c.limitedTotal??''}"></label></div><small class="limitInfo">${c.limitedTotal==null?'무제한 발급':`전체 발급 ${c.issuedCount||0} / ${c.limitedTotal} · 전체 남은 수량 ${Math.max(0,c.limitedTotal-(c.issuedCount||0))}`}</small><label><input class="active" type="checkbox" ${c.is_active?'checked':''} ${['RETIRE_PENDING','RETIRED'].includes(c.cardStatus)?'disabled':''}> 게임에 노출</label>${c.cardStatus==='RETIRE_PENDING'?'<div class="inlineNotice dangerNotice">퇴사 삭제 대기 · 신규 획득 차단 · 환급 메시지 생성 완료</div>':c.cardStatus==='RETIRED'?'<div class="inlineNotice">퇴사 처리 완료 · 게임 비노출</div>':''}<div class="row"><button class="save" ${['RETIRE_PENDING','RETIRED'].includes(c.cardStatus)?'disabled':''}>저장</button>${state.role==='OWNER'?(c.cardStatus==='RETIRE_PENDING'?'<button class="retire danger">퇴사 확정</button>':c.cardStatus==='RETIRED'?'':'<button class="retire warn">퇴사 처리</button>'):''}</div></div></article>`}
function updateBulkCardSaveState(){const btn=$('#saveAllCardsBtn'),count=$('#dirtyCardCount'),n=state.dirtyCardIds.size;if(btn){btn.disabled=n===0;btn.textContent=n?`변경 카드 ${n}장 한 번에 저장`:'변경사항 없음'}if(count)count.textContent=n?`${n}장 수정됨`:'수정 대기 없음'}
function markCardDirty(el){if(!el||['RETIRE_PENDING','RETIRED'].includes(state.cards.find(x=>String(x.id)===String(el.dataset.id))?.cardStatus))return;state.dirtyCardIds.add(String(el.dataset.id));el.classList.add('cardDirty');el.querySelector('.save')?.classList.add('warn');updateBulkCardSaveState()}
function cardPowerFor(grade,type){return ({SSR:{NORMAL:1300,HIGH:1375,TOP:1450},MA:{NORMAL:1850,HIGH:2050,TOP:2250},LIMITED:{NORMAL:2350,HIGH:2600,TOP:2850},FUR:{FIXED:3200}}[grade]||{})[grade==='FUR'?'FIXED':type]||null}
function updateCardPowerPreview(el){const grade=el.querySelector('.rarity')?.value,type=el.querySelector('.powerType')?.value,power=cardPowerFor(grade,type),preview=el.querySelector('.powerPreview');if(preview)preview.textContent=power?`기본 전투력 ${Number(power).toLocaleString()}`:'유형을 선택하면 자동 적용'}
function bindCardEditors(scope=document){scope.querySelectorAll('.adminCard').forEach(el=>{if(el.dataset.bound==='1')return;el.dataset.bound='1';el.querySelector('.save')?.addEventListener('click',()=>saveCard(el));el.querySelector('.retire')?.addEventListener('click',()=>retireCard(el.dataset.id,state.cards.find(x=>String(x.id)===String(el.dataset.id))?.cardStatus));const rarity=el.querySelector('.rarity'),limit=el.querySelector('.limit');rarity?.addEventListener('change',()=>{if(rarity.value!=='LIMITED'&&limit){limit.value='';limit.disabled=true}else if(limit){limit.disabled=false}updateCardPowerPreview(el);markCardDirty(el)});el.querySelector('.powerType')?.addEventListener('change',()=>updateCardPowerPreview(el));if(rarity&&limit)limit.disabled=rarity.value!=='LIMITED';el.querySelectorAll('input,select').forEach(input=>{if(input===rarity)return;input.addEventListener(input.type==='checkbox'||input.tagName==='SELECT'?'change':'input',()=>markCardDirty(el))})})}
function filteredCards(){const q=($('#cardSearch')?.value||'').trim().toLowerCase(),g=$('#grade')?.value||'';return state.cards.filter(c=>c.cardStatus!=='PENDING'&&(!q||String(c.title||'').toLowerCase().includes(q)||String(c.name||'').toLowerCase().includes(q))&&(!g||c.grade===g))}
function renderCards(){document.querySelectorAll('[data-card-view]').forEach(b=>b.classList.toggle('active',b.dataset.cardView===state.cardManageView));const box=$('#cards'),list=filteredCards();if(state.cardManageView==='ALL'){box.className='cards';box.innerHTML=list.length?list.map(cardEditorMarkup).join(''):'<div class="panel muted">검색 조건에 맞는 카드가 없습니다.</div>';bindCardEditors(box);return}if(state.cardManageView==='GRADES'){const groups=RARITIES.map(g=>[g,list.filter(c=>c.grade===g)]).filter(x=>x[1].length);box.className='cardGroupList';box.innerHTML=groups.length?groups.map(([g,cards])=>`<section class="memberCardGroup"><div class="memberGroupHead"><div><span class="gradeBadge grade-${g}">${g}</span><h3>${g} 등급</h3><p>총 ${cards.length}장</p></div><button class="ghost groupToggle">펼치기</button></div><div class="cards groupCards" hidden>${cards.map(cardEditorMarkup).join('')}</div></section>`).join(''):'<div class="panel muted">해당 등급 카드가 없습니다.</div>';bindGroupToggles(box);return}if(state.cardManageView==='RETIRE'){renderRetirementManager(list);return}renderMemberGroups(list)}
function bindGroupToggles(box){box.querySelectorAll('.memberCardGroup').forEach(sec=>{const btn=sec.querySelector('.groupToggle'),cards=sec.querySelector('.groupCards');btn.onclick=()=>{cards.hidden=!cards.hidden;btn.textContent=cards.hidden?'펼치기':'접기';if(!cards.hidden)bindCardEditors(cards)}})}
function renderMemberGroups(list){const groups=new Map();for(const c of list){if(!groups.has(c.memberId))groups.set(c.memberId,{memberId:c.memberId,name:c.name,cards:[]});groups.get(c.memberId).cards.push(c)}const rows=[...groups.values()].sort((a,b)=>String(a.name).localeCompare(String(b.name),'ko'));const box=$('#cards');box.className='cardGroupList';box.innerHTML=rows.length?rows.map(g=>{const active=g.cards.filter(c=>c.is_active&&!['RETIRE_PENDING','RETIRED'].includes(c.cardStatus)).length,pending=g.cards.filter(c=>c.cardStatus==='RETIRE_PENDING').length,retired=g.cards.filter(c=>c.cardStatus==='RETIRED').length;return `<section class="memberCardGroup" data-member-id="${g.memberId}"><div class="memberGroupHead"><div><small>MEMBER CARD GROUP</small><h3>${esc(g.name)}</h3><p>카드 ${g.cards.length}종 · 활성 ${active} · 삭제 대기 ${pending} · 퇴사 완료 ${retired}</p></div><div class="memberGroupActions"><button class="ghost groupToggle">카드 보기</button>${state.role==='OWNER'&&g.cards.some(c=>!['RETIRE_PENDING','RETIRED'].includes(c.cardStatus))?'<button class="warn retireMemberBtn">멤버 퇴사 처리</button>':''}</div></div><div class="memberGradeStrip">${RARITIES.map(r=>{const n=g.cards.filter(c=>c.grade===r).length;return n?`<span><b>${r}</b>${n}</span>`:''}).join('')}</div><div class="cards groupCards" hidden>${g.cards.sort((a,b)=>RARITIES.indexOf(a.grade)-RARITIES.indexOf(b.grade)).map(cardEditorMarkup).join('')}</div></section>`}).join(''):'<div class="panel muted">검색 조건에 맞는 멤버 카드가 없습니다.</div>';bindGroupToggles(box);box.querySelectorAll('.retireMemberBtn').forEach(btn=>btn.onclick=()=>retireMemberCards(btn.closest('.memberCardGroup').dataset.memberId))}
async function retireMemberCards(memberId){const cards=state.cards.filter(c=>String(c.memberId)===String(memberId)&&c.cardStatus!=='PENDING'&&!['RETIRE_PENDING','RETIRED'].includes(c.cardStatus));if(!cards.length)return alert('퇴사 처리 가능한 카드가 없습니다.');const member=cards[0].name;let totalUsers=0,totalRefund=0,previews=[];for(const c of cards){const p=await api('admin/card-retirement',{method:'POST',body:JSON.stringify({cardId:c.id,action:'PREVIEW'})});previews.push({card:c,summary:p.summary});totalUsers+=Number(p.summary.refundUsers||0);totalRefund+=Number(p.summary.totalRefundShards||0)}if(!confirm(`${member} 멤버 카드 ${cards.length}종을 삭제 대기로 등록할까요?\n환급 메시지 대상 합계 ${totalUsers}건\n예상 환급 카드조각 ${totalRefund.toLocaleString()}개\n\n강화 실패 횟수는 계산하지 않습니다.`))return;let sent=0;for(const x of previews){const d=await api('admin/card-retirement',{method:'POST',body:JSON.stringify({cardId:x.card.id,action:'QUEUE'})});sent+=Number(d.sent||0)}alert(`${member} 카드 ${cards.length}종 삭제 대기 등록 완료\n환급 메시지 ${sent}건 생성`);await loadCards()}
function renderRetirementManager(list){const box=$('#cards'),pending=list.filter(c=>c.cardStatus==='RETIRE_PENDING'),done=list.filter(c=>c.cardStatus==='RETIRED'),available=list.filter(c=>!['RETIRE_PENDING','RETIRED'].includes(c.cardStatus));const members=[...new Map(available.map(c=>[c.memberId,c.name])).entries()].sort((a,b)=>String(a[1]).localeCompare(String(b[1]),'ko'));box.className='retirementManager';box.innerHTML=`<section class="panel retirementHero"><div><small>RETIREMENT CONTROL · OWNER ONLY</small><h2>퇴사·삭제 관리</h2><p>멤버 또는 카드 단위로 삭제 대기를 등록하고, 강화 단계 기준 재료의 50%를 메시지로 환급합니다.</p></div>${state.role==='OWNER'?`<div class="retireMemberSelect"><select id="retireMemberSelect"><option value="">멤버 선택</option>${members.map(([id,name])=>`<option value="${id}">${esc(name)}</option>`).join('')}</select><button id="retireSelectedMemberBtn" class="warn">선택 멤버 전체 퇴사 처리</button></div>`:'<div class="inlineNotice">퇴사 처리는 OWNER만 가능합니다.</div>'}</section><div class="retirementStats"><div><small>처리 가능 카드</small><b>${available.length}</b></div><div><small>삭제 대기</small><b>${pending.length}</b></div><div><small>퇴사 완료</small><b>${done.length}</b></div></div><section class="panel"><div class="maintenanceHead"><div><h2>삭제 대기 카드</h2><p>환급 메시지가 생성되어 최종 확정을 기다리는 카드입니다.</p></div></div><div class="retirementRows">${pending.length?pending.map(c=>retirementRow(c,true)).join(''):'<div class="muted">삭제 대기 카드가 없습니다.</div>'}</div></section><section class="panel"><div class="maintenanceHead"><div><h2>퇴사 처리 가능한 카드</h2><p>개별 카드 단위로도 환급 미리보기 후 삭제 대기를 등록할 수 있습니다.</p></div></div><div class="retirementRows">${available.length?available.map(c=>retirementRow(c,false)).join(''):'<div class="muted">처리 가능한 카드가 없습니다.</div>'}</div></section><section class="panel"><div class="maintenanceHead"><div><h2>퇴사 완료 기록</h2><p>물리 삭제하지 않고 기존 기록을 안전하게 보존합니다.</p></div></div><div class="retirementRows compact">${done.length?done.map(c=>retirementRow(c,false,true)).join(''):'<div class="muted">퇴사 완료 카드가 없습니다.</div>'}</div></section>`;$('#retireSelectedMemberBtn')?.addEventListener('click',()=>{const id=$('#retireMemberSelect').value;if(!id)return alert('멤버를 선택하세요.');retireMemberCards(id)});box.querySelectorAll('[data-retire-card]').forEach(btn=>btn.onclick=()=>retireCard(btn.dataset.retireCard,btn.dataset.status))}
function retirementRow(c,isPending,isDone=false){return `<article class="retirementRow"><img src="${esc(img(c.image))}" style="object-position:${c.focusX}% ${c.focusY}%"><div><b>${esc(c.name)} · ${esc(c.title)}</b><span>${esc(c.grade)} · ${cardStatusLabel(c)}</span></div>${state.role==='OWNER'&&!isDone?`<button data-retire-card="${c.id}" data-status="${esc(c.cardStatus||'')}" class="${isPending?'danger':'warn'}">${isPending?'퇴사 확정':'환급 미리보기·삭제 대기'}</button>`:''}</article>`}
function collectCardPayload(el){const grade=el.querySelector('.rarity').value;const limitInput=el.querySelector('.limit');const limitedTotal=grade==='LIMITED'?(limitInput.value===''?null:Number(limitInput.value)):null;const powerType=el.querySelector('.powerType')?.value||null;return {id:el.dataset.id,memberId:Number(el.querySelector('.member').value),title:el.querySelector('.title').value.trim(),grade,image:el.querySelector('.image').value.trim(),focusX:Number(el.querySelector('.fx').value),focusY:Number(el.querySelector('.fy').value),isActive:el.querySelector('.active').checked,cardStatus:el.querySelector('.active').checked?'PUBLIC':'INACTIVE',drawWeight:Number(el.querySelector('.weight').value),limitedTotal,powerType}}
function applySavedCardToState(payload){const c=state.cards.find(x=>String(x.id)===String(payload.id));if(!c)return;c.memberId=payload.memberId;c.title=payload.title;c.grade=payload.grade;c.image=payload.image;c.focusX=payload.focusX;c.focusY=payload.focusY;c.is_active=payload.isActive?1:0;c.cardStatus=payload.cardStatus;c.drawWeight=payload.drawWeight;c.limitedTotal=payload.limitedTotal;c.powerType=payload.powerType;c.basePower=cardPowerFor(payload.grade,payload.powerType)}
async function saveCard(el){const btn=el.querySelector('.save'),payload=collectCardPayload(el);setBusy(btn,true,'저장 중...');try{await api('admin/cards',{method:'PATCH',body:JSON.stringify(payload)});applySavedCardToState(payload);state.dirtyCardIds.delete(String(payload.id));el.classList.remove('cardDirty');btn.classList.remove('warn');updateBulkCardSaveState();const old=btn.dataset.label||'저장';btn.textContent='저장 완료';setTimeout(()=>{btn.textContent=old;btn.disabled=false},700)}catch(e){btn.disabled=false;btn.textContent=btn.dataset.label||'저장';throw e}}
async function saveAllChangedCards(){const btn=$('#saveAllCardsBtn'),ids=[...state.dirtyCardIds],scrollY=window.scrollY;if(!ids.length)return;const editors=ids.map(id=>document.querySelector(`.adminCard[data-id="${CSS.escape(id)}"]`)).filter(Boolean);if(!editors.length)return alert('현재 화면에서 수정된 카드를 찾지 못했습니다.');if(!confirm(`수정한 카드 ${editors.length}장을 한 번에 저장할까요?`))return;setBusy(btn,true,`0 / ${editors.length} 저장 중`);let done=0,failed=[];for(const el of editors){const payload=collectCardPayload(el);try{await api('admin/cards',{method:'PATCH',body:JSON.stringify(payload)});applySavedCardToState(payload);state.dirtyCardIds.delete(String(payload.id));el.classList.remove('cardDirty');el.querySelector('.save')?.classList.remove('warn');done++;btn.textContent=`${done} / ${editors.length} 저장 중`}catch(e){failed.push(`${payload.title||payload.id}: ${e.message}`)}}updateBulkCardSaveState();window.scrollTo(0,scrollY);if(failed.length)alert(`일괄 저장 완료 ${done}장 / 실패 ${failed.length}장\n\n${failed.slice(0,8).join('\n')}`);else alert(`${done}장 일괄 저장 완료\n현재 화면과 위치는 그대로 유지됩니다.`)}
async function retireCard(id,status){
  try{
    if(status==='RETIRE_PENDING'){
      if(!confirm('환급 메시지 생성이 완료된 카드입니다. 퇴사 처리를 최종 확정할까요?\n카드는 게임에서 계속 비노출되며 기록은 안전하게 보존됩니다.'))return;
      await api('admin/card-retirement',{method:'POST',body:JSON.stringify({cardId:id,action:'FINALIZE'})});alert('퇴사 카드 처리가 최종 확정되었습니다.');await loadCards();return;
    }
    const p=await api('admin/card-retirement',{method:'POST',body:JSON.stringify({cardId:id,action:'PREVIEW'})}),s=p.summary;
    const text=`퇴사 카드 삭제 대기 처리\n\n카드: ${s.memberName} · ${s.title} [${s.grade}]\n보유 유저: ${s.ownedUsers}명\n환급 대상: ${s.refundUsers}명\n강화 단계 기준 누적 필요 재료: ${Number(s.totalRequiredShards).toLocaleString()}개\n50% 환급 예정: ${Number(s.totalRefundShards).toLocaleString()}개\n\n강화 실패 횟수는 계산하지 않습니다.\n카드를 즉시 게임에서 숨기고 환급 메시지를 생성할까요?`;
    if(!confirm(text))return;
    const d=await api('admin/card-retirement',{method:'POST',body:JSON.stringify({cardId:id,action:'QUEUE'})});alert(`삭제 대기 등록 완료\n환급 메시지 ${d.sent}건 생성`);await loadCards();
  }catch(e){alert(e.message)}
}
async function deleteCard(id){if(!confirm('이 카드를 완전히 삭제할까요?\n유저 보유 기록에도 영향을 줄 수 있습니다.'))return;await api('admin/cards',{method:'DELETE',body:JSON.stringify({id})});await loadCards()}
async function addCard(){const p={memberId:Number($('#memberId').value),title:$('#cardTitle').value.trim(),grade:$('#cardGrade').value,image:$('#cardImage').value.trim(),focusX:Number($('#cardFx').value),focusY:Number($('#cardFy').value),isActive:false,cardStatus:'PENDING',batchName:'CMS 직접 추가',batchDate:new Date().toISOString().slice(0,10),drawWeight:Number($('#cardWeight').value||1),limitedTotal:$('#cardLimit').value===''?null:Number($('#cardLimit').value)};await api('admin/cards',{method:'POST',body:JSON.stringify(p)});$('#cardDialog').close();await loadCards();alert('새 카드가 대기 카드함에 추가되었습니다.')}

function updatePendingCount(){const n=state.cards.filter(c=>c.cardStatus==='PENDING').length;const a=$('#pendingNavCount'),b=$('#pendingTitleCount');if(a)a.textContent=n;if(b)b.textContent=`(${n})`}
async function loadPending(){if(!state.cards.length){const d=await api('admin/cards');state.cards=d.cards;state.members=d.members}updatePendingCount();renderPending()}
function renderPending(){const pending=state.cards.filter(c=>c.cardStatus==='PENDING');const groups={};for(const c of pending){const key=`${c.batchDate||'날짜 미지정'}|${c.batchName||'신규 카드'}`;(groups[key]??=[]).push(c)}$('#pendingBatches').innerHTML=pending.length?Object.entries(groups).map(([key,cards])=>{const [date,name]=key.split('|');return `<section class="pendingBatch panel"><div class="pendingBatchHead"><div><small>추가일: ${esc(date)}</small><h3>${esc(name)}</h3><p>총 ${cards.length}장</p></div><label><input class="batchSelect" data-batch="${esc(key)}" type="checkbox"> 묶음 전체 선택</label></div><div class="pendingGrid">${cards.map(c=>`<article class="pendingCard" data-id="${c.id}" data-batch="${esc(key)}"><label class="pendingCheck"><input type="checkbox" class="pendingItem"> 선택</label><img src="${esc(img(c.image))}" style="object-position:${c.focusX}% ${c.focusY}%"><div class="pendingSummary"><b>${esc(c.title)}</b><span>${esc(c.name)} · ${esc(c.grade)}</span><span>${c.limitedTotal!=null?'한정판':'일반'}${c.limitedTotal!=null?` · 총 ${c.limitedTotal}장`:''}</span><em>상태: 대기</em><button type="button" class="pendingEditToggle ghost">정보 수정</button></div><div class="pendingEdit" hidden><label>카드명<input class="pTitle" value="${esc(c.title)}"></label><label>멤버<select class="pMember">${state.members.map(m=>`<option value="${m.id}" ${m.id==c.memberId?'selected':''}>${esc(m.name)}</option>`).join('')}</select></label><label>등급<select class="pRarity">${RARITIES.map(r=>`<option ${r===c.grade?'selected':''}>${r}</option>`).join('')}</select></label><label>이미지 경로<input class="pImage" value="${esc(c.image)}"></label><div class="row"><label>가로 위치<input class="pFx" type="number" value="${c.focusX}"></label><label>세로 위치<input class="pFy" type="number" value="${c.focusY}"></label></div><div class="row"><label>개별 가중치<input class="pWeight" type="number" min="0" step="0.01" value="${c.drawWeight??1}"></label><label>한정 총수량<input class="pLimit" type="number" min="0" placeholder="무제한" value="${c.limitedTotal??''}"></label></div><div class="row"><button type="button" class="pendingSave">대기 상태로 저장</button><button type="button" class="pendingCancel ghost">닫기</button></div></div></article>`).join('')}</div></section>`}).join(''):'<div class="panel muted">현재 검수 대기 중인 신규 카드가 없습니다.</div>';document.querySelectorAll('.batchSelect').forEach(x=>x.onchange=()=>{document.querySelectorAll(`.pendingCard[data-batch="${CSS.escape(x.dataset.batch)}"] .pendingItem`).forEach(i=>i.checked=x.checked);syncPendingSelectAll()});document.querySelectorAll('.pendingItem').forEach(x=>x.onchange=syncPendingSelectAll);document.querySelectorAll('.pendingCard').forEach(el=>{const edit=el.querySelector('.pendingEdit'),summary=el.querySelector('.pendingSummary');el.querySelector('.pendingEditToggle').onclick=()=>{edit.hidden=false;summary.hidden=true};el.querySelector('.pendingCancel').onclick=()=>{edit.hidden=true;summary.hidden=false};el.querySelector('.pendingSave').onclick=()=>savePendingCard(el)});$('#pendingSelectAll').checked=false}
async function savePendingCard(el){const btn=el.querySelector('.pendingSave');const p={id:el.dataset.id,memberId:Number(el.querySelector('.pMember').value),title:el.querySelector('.pTitle').value.trim(),grade:el.querySelector('.pRarity').value,image:el.querySelector('.pImage').value.trim(),focusX:Number(el.querySelector('.pFx').value),focusY:Number(el.querySelector('.pFy').value),isActive:false,cardStatus:'PENDING',drawWeight:Number(el.querySelector('.pWeight').value||1),limitedTotal:el.querySelector('.pLimit').value===''?null:Number(el.querySelector('.pLimit').value)};if(!p.title||!p.image)return alert('카드명과 이미지 경로를 입력하세요.');setBusy(btn,true,'저장 중...');try{await api('admin/cards',{method:'PATCH',body:JSON.stringify(p)});state.cards=[];await loadPending();alert('대기 카드 정보가 저장되었습니다.')}catch(e){alert(e.message)}finally{setBusy(btn,false)}}
function selectedPendingIds(){return [...document.querySelectorAll('.pendingCard .pendingItem:checked')].map(x=>x.closest('.pendingCard').dataset.id)}
function syncPendingSelectAll(){const all=[...document.querySelectorAll('.pendingItem')];$('#pendingSelectAll').checked=all.length>0&&all.every(x=>x.checked)}
async function bulkPendingStatus(status){const ids=selectedPendingIds();if(!ids.length)return alert('처리할 카드를 선택하세요.');const label={PUBLIC:'공개',INACTIVE:'비활성'}[status];if(!confirm(`선택한 ${ids.length}장을 ${label} 처리할까요?`))return;await api('admin/cards',{method:'PATCH',body:JSON.stringify({ids,status})});state.cards=[];await loadPending();alert(`${ids.length}장 ${label} 처리가 완료되었습니다.`)}
async function bulkPendingDelete(){const ids=selectedPendingIds();if(!ids.length)return alert('삭제할 카드를 선택하세요.');if(state.role!=='OWNER')return alert('완전 삭제는 OWNER만 가능합니다.');if(!confirm(`선택한 ${ids.length}장을 완전히 삭제할까요?`))return;await api('admin/cards',{method:'DELETE',body:JSON.stringify({ids})});state.cards=[];await loadPending();alert(`${ids.length}장이 삭제되었습니다.`)}

function packPreviewConfig(id){return state.packData?.previews?.[id]||{badge:'NEW UPDATE',headline:'신규 카드 업데이트',showNewCards:true,showNames:true,showGrades:true,columns:5,cardIds:[]}}
function selectedPack(){return state.packData?.packs?.find(p=>p.id===state.selectedPackId)||state.packData?.packs?.[0]}
function selectedPityConfig(){const id=selectedPack()?.id;const base={enabled:true,start:61,hard:70,rates:{61:10,62:15,63:20,64:25,65:30,66:35,67:40,68:45,69:50,70:100}};return {...base,...(state.packData?.pitySettings?.[id]||{}),rates:{...base.rates,...(state.packData?.pitySettings?.[id]?.rates||{})}}}
function pityManagerMarkup(packId){if(!['premium','pickup'].includes(packId))return '';const c=selectedPityConfig();const rows=[];for(let n=c.start;n<=c.hard;n++)rows.push(`<label class="pityRateField"><span>${n}회</span><input class="pityRateInput" data-draw="${n}" type="number" min="0" max="100" step="0.1" value="${n===c.hard?100:Number(c.rates?.[n]??0)}" ${n===c.hard?'readonly':''}></label>`);return `<section class="pityManager"><div class="pityHead"><div><h3>SSR 천장 설정</h3><p>${packId==='premium'?'프리미엄팩':'리미티드팩'} 전용 천장입니다. SSR 이상 획득 시 카운트가 초기화됩니다.</p></div><label class="pityToggle"><input id="pityEnabled" type="checkbox" ${c.enabled!==false?'checked':''}> 사용</label></div><div class="pityCore"><label class="field"><span>소프트 천장 시작</span><input id="pityStart" type="number" min="1" max="999" value="${c.start}"></label><label class="field"><span>확정 천장</span><input id="pityHard" type="number" min="1" max="999" value="${c.hard}"></label></div><div class="pityRates">${rows.join('')}</div><small>확정 천장 회차는 항상 SSR 100%로 저장됩니다. 프리미엄팩과 리미티드팩은 각각 독립 카운트입니다.</small></section>`}
function currentPityDraft(){const p=selectedPack();if(!p||!['premium','pickup'].includes(p.id))return null;const start=Math.max(1,Math.floor(Number($('#pityStart')?.value||61))),hard=Math.max(start,Math.floor(Number($('#pityHard')?.value||70))),rates={};document.querySelectorAll('.pityRateInput').forEach(x=>rates[x.dataset.draw]=Number(x.value)||0);rates[hard]=100;return {enabled:$('#pityEnabled')?.checked!==false,start,hard,rates}}
function renderPackManager(){
  const d=state.packData;if(!d)return;const p=selectedPack();if(!p)return;const cfg=packPreviewConfig(p.id);
  $('#packManager').innerHTML=`<div class="packAdminHead"><div><h3>카드팩 세부 설정 · 캡처 미리보기</h3><p>실제 게임 카드팩 화면과 같은 구성으로 CMS 안에서 확인하고 캡처할 수 있습니다. 미리보기는 유저 화면에 공개되지 않습니다.</p></div><select id="detailPackSelect">${d.packs.map(x=>`<option value="${x.id}" ${x.id===p.id?'selected':''}>${esc(x.name)}</option>`).join('')}</select></div><div class="packAdminLayout"><div class="packAdminForm"><div class="formgrid"><label class="field"><span>팩 이름</span><input id="pdName" value="${esc(p.name)}"></label><label class="field"><span>영문명</span><input id="pdSubtitle" value="${esc(p.subtitle)}"></label><label class="field full"><span>팩 설명</span><textarea id="pdDescription" rows="3">${esc(p.description)}</textarea></label><label class="field"><span>가격</span><input id="pdPrice" type="number" min="0" value="${p.price}"></label><label class="field"><span>테마</span><select id="pdTheme">${['basic','advanced','premium','pickup'].map(x=>`<option ${x===p.theme?'selected':''}>${x}</option>`).join('')}</select></label><label class="field"><span>10연속 보장</span><select id="pdG10">${RARITIES.slice().reverse().map(x=>`<option ${x===p.guarantee_10?'selected':''}>${x}</option>`).join('')}</select></label><label class="field"><span>20연속 보장</span><select id="pdG20">${RARITIES.slice().reverse().map(x=>`<option ${x===p.guarantee_20?'selected':''}>${x}</option>`).join('')}</select></label><label class="field"><span>사용 상태</span><select id="pdActive"><option value="1" ${p.is_active?'selected':''}>판매 중</option><option value="0" ${p.is_active?'':'selected'}>판매 중지</option></select></label><label class="field"><span>정렬 순서</span><input id="pdSort" type="number" value="${p.sort_order||0}"></label><label class="field"><span>캡처 배지</span><input id="pvBadge" value="${esc(cfg.badge||'')}"></label><label class="field"><span>캡처 제목</span><input id="pvHeadline" value="${esc(cfg.headline||'')}"></label><label class="field"><span>한 줄 카드 수</span><input id="pvColumns" type="number" min="2" max="6" value="${cfg.columns||5}"></label></div>${pityManagerMarkup(p.id)}<div class="previewOptions"><label><input id="pvShowCards" type="checkbox" ${cfg.showNewCards!==false?'checked':''}> 신규 카드 영역 표시</label><label><input id="pvShowNames" type="checkbox" ${cfg.showNames!==false?'checked':''}> 카드 이름 표시</label><label><input id="pvShowGrades" type="checkbox" ${cfg.showGrades!==false?'checked':''}> 등급 표시</label></div><div class="previewCardPicker"><b>미리보기에 표시할 카드</b><div>${d.cards.map(c=>`<label><input class="pvCard" type="checkbox" value="${c.id}" ${(cfg.cardIds||[]).includes(c.id)?'checked':''}><img src="${esc(img(c.image))}"><span>${esc(c.name)}<small>${esc(c.grade)} · ${esc(c.title)}</small></span></label>`).join('')}</div></div><div class="packAdminActions"><button id="savePackDetailBtn">팩 설정 저장</button><button id="openPackPreviewBtn" class="ghost">전체 화면 캡처 미리보기</button></div></div><div id="inlinePackPreview" class="inlinePackPreview"></div></div>`;
  $('#detailPackSelect').onchange=e=>{state.selectedPackId=e.target.value;renderPackManager()};
  document.querySelectorAll('#packManager input,#packManager textarea,#packManager select').forEach(x=>{if(x.id!=='detailPackSelect')x.addEventListener('input',renderInlinePackPreview)});
  $('#pityStart')?.addEventListener('change',renderPackManager);$('#pityHard')?.addEventListener('change',renderPackManager);
  $('#savePackDetailBtn').onclick=savePackDetails;$('#openPackPreviewBtn').onclick=openPackPreview;renderInlinePackPreview();
}
function currentPackDraft(){const p=selectedPack();return {...p,name:$('#pdName').value.trim(),subtitle:$('#pdSubtitle').value.trim(),description:$('#pdDescription').value.trim(),price:Number($('#pdPrice').value)||0,theme:$('#pdTheme').value,guarantee_10:$('#pdG10').value,guarantee_20:$('#pdG20').value,is_active:$('#pdActive').value==='1',sort_order:Number($('#pdSort').value)||0}}
function currentPreviewDraft(){return {badge:$('#pvBadge').value.trim(),headline:$('#pvHeadline').value.trim(),showNewCards:$('#pvShowCards').checked,showNames:$('#pvShowNames').checked,showGrades:$('#pvShowGrades').checked,columns:Number($('#pvColumns').value)||5,cardIds:[...document.querySelectorAll('.pvCard:checked')].map(x=>x.value)}}
function previewPackImagePath(p){const files={basic:'standard-pack.png',advanced:'advanced-pack.png',premium:'premium-pack.png',pickup:'limited-pack.png'};return `../assets/ui/packs/${files[p.id]||files[p.theme]||files.basic}`}
function previewPackArt(p){return `<div class="cmsPackEnvelope cmsPackImageEnvelope ${esc(p.theme)}"><img src="${previewPackImagePath(p)}" alt="${esc(p.name)}"><div class="cmsPackImageGloss"></div></div>`}
function previewMarkup(full=false){const p=currentPackDraft(),cfg=currentPreviewDraft();const cards=(state.packData.cards||[]).filter(c=>cfg.cardIds.includes(c.id));return `<div class="cmsGamePreview ${full?'capture':''} theme-${esc(p.theme)}"><div class="cmsPreviewTop"><div><small>CNINE CARD COLLECTION</small><h1>씨켓몬 카드뽑기</h1></div><div class="cmsFakeNav">카드팩　도감　전투　접속보상　랭킹</div></div><div class="cmsPreviewSelector"><small>SELECT CARD PACK</small><b>${esc(p.name)}</b><span>${esc(p.description)}</span></div><section class="cmsPreviewHero"><div class="cmsPreviewCopy">${cfg.badge?`<em>${esc(cfg.badge)}</em>`:''}<small>${esc(p.subtitle)}</small><h2>${esc(p.name)}을<br><strong>개봉하세요</strong></h2><p>${esc(p.description)}<br>10연속 ${esc(p.guarantee_10)} 이상 1장 · 20연속 ${esc(p.guarantee_20)} 이상 1장 보장</p><div><button>1 CARD<br>${p.price}코인</button><button>10 CARDS · ${esc(p.guarantee_10)}+<br>${(p.price*10).toLocaleString()}코인</button><button>20 CARDS · ${esc(p.guarantee_20)}+<br>${(p.price*20).toLocaleString()}코인</button></div></div><div class="cmsPreviewPack">${previewPackArt(p)}</div></section>${cfg.showNewCards?`<section class="cmsNewCards"><div><small>NEW CARD PREVIEW</small><h2>${esc(cfg.headline||'신규 카드 업데이트')}</h2></div><div class="cmsNewCardGrid" style="--cols:${cfg.columns}">${cards.length?cards.map(c=>`<article><div class="cmsGrade ${esc(c.grade)}">${cfg.showGrades?esc(c.grade):''}</div><img src="${esc(img(c.image))}">${cfg.showNames?`<b>${esc(c.name)}</b><span>${esc(c.title)}</span>`:''}</article>`).join(''):'<p class="cmsNoCards">왼쪽에서 공개할 카드를 선택하세요.</p>'}</div></section>`:''}<div class="cmsCaptureNote">CMS 캡처 전용 미리보기 · 실제 유저 화면에는 표시되지 않습니다.</div></div>`}
function renderInlinePackPreview(){const el=$('#inlinePackPreview');if(el)el.innerHTML=previewMarkup(false)}
function openPackPreview(){let overlay=$('#packPreviewOverlay');if(!overlay){overlay=document.createElement('div');overlay.id='packPreviewOverlay';overlay.className='packPreviewOverlay';document.body.appendChild(overlay)}overlay.innerHTML=`<div class="captureToolbar"><button id="previewClose">닫기 (ESC)</button><button data-size="desktop">PC</button><button data-size="wago">와고</button><button data-size="mobile">모바일</button></div><div class="captureViewport desktop" id="captureViewport">${previewMarkup(true)}</div>`;overlay.classList.add('open');$('#previewClose').onclick=()=>overlay.classList.remove('open');overlay.querySelectorAll('[data-size]').forEach(b=>b.onclick=()=>{$('#captureViewport').className='captureViewport '+b.dataset.size});document.onkeydown=e=>{if(e.key==='Escape')overlay.classList.remove('open')}}
async function savePackDetails(){const p=currentPackDraft(),preview=currentPreviewDraft(),pitySettings=currentPityDraft(),btn=$('#savePackDetailBtn');setBusy(btn,true,'저장 중...');try{await api('admin/card-packs',{method:'PATCH',body:JSON.stringify({id:p.id,name:p.name,subtitle:p.subtitle,description:p.description,theme:p.theme,price:p.price,guarantee10:p.guarantee_10,guarantee20:p.guarantee_20,isActive:p.is_active,sortOrder:p.sort_order,preview,pitySettings})});alert(pitySettings?'카드팩 설정과 SSR 천장 설정이 저장되었습니다.':'카드팩 세부 설정이 저장되었습니다.');await loadCards()}finally{setBusy(btn,false)}}

function renderRateManager(){
  const d=state.rateData;if(!d)return;
  $('#rateManager').innerHTML=`<div class="rateHead"><div><h3>카드팩 확률 관리</h3><p>일반 등급(C~FUR)은 합계 100%로 저장됩니다. 리미티드팩의 LIMITED는 이 합계에서 제외되는 별도 당첨 확률입니다.</p></div><select id="ratePack">${d.packs.map(p=>`<option value="${p.id}">${esc(p.name)}</option>`).join('')}</select></div><div id="rateFields" class="rateFields"></div><div id="limitedRateBox"></div><div class="rateFoot"><b>일반 등급 합계 <span id="rateTotal">0</span>%</b><button id="saveRatesBtn">확률 저장</button></div>`;
  $('#ratePack').onchange=renderRateFields;$('#saveRatesBtn').onclick=saveRates;renderRateFields();
}
function renderRateFields(){
  const packId=$('#ratePack').value;const map=Object.fromEntries(state.rateData.rates.filter(x=>x.pack_id===packId).map(x=>[x.rarity,x.rate]));
  const normal=RARITIES.filter(r=>r!=='LIMITED');
  $('#rateFields').innerHTML=normal.map(r=>`<label class="field"><span>${r} 등급</span><input class="rateInput" data-rarity="${r}" type="number" min="0" max="100" step="0.0001" value="${Number(map[r]||0)}"></label>`).join('');
  $('#limitedRateBox').innerHTML=packId==='pickup'?`<div class="panel" style="margin-top:14px"><label class="field"><span>LIMITED 별도 등장 확률 (%)</span><input id="limitedRateInput" data-rarity="LIMITED" type="number" min="0" max="100" step="0.0001" value="${Number(map.LIMITED||0)}"></label><small>일반 등급 100% 합계에 포함되지 않습니다. 당첨 시 남은 수량이 있는 한정판 중 카드별 가중치로 1장이 지급되며, 전부 품절이면 일반 카드가 지급됩니다.</small></div>`:`<input id="limitedRateInput" data-rarity="LIMITED" type="hidden" value="0">`;
  document.querySelectorAll('.rateInput').forEach(x=>x.oninput=updateRateTotal);updateRateTotal();
}
function updateRateTotal(){const total=[...document.querySelectorAll('.rateInput')].reduce((a,x)=>a+(Number(x.value)||0),0);$('#rateTotal').textContent=total.toFixed(4).replace(/0+$/,'').replace(/\.$/,'');$('#rateTotal').className=Math.abs(total-100)<.0001?'ok':'bad'}
async function saveRates(){const packId=$('#ratePack').value;const rates=Object.fromEntries([...document.querySelectorAll('.rateInput')].map(x=>[x.dataset.rarity,Number(x.value)||0]));rates.LIMITED=Number($('#limitedRateInput')?.value)||0;await api('admin/card-rates',{method:'PATCH',body:JSON.stringify({packId,rates})});state.rateData=await api('admin/card-rates');renderRateManager();alert(packId==='pickup'?'일반 확률과 한정판 별도 확률이 저장되었습니다.':'카드팩 확률이 저장되었습니다.');}


async function loadRaidAdmin(){const d=await api('admin/raid');state.raidData=d;const s=d.settings||{};const set=(id,v)=>{const e=$(id);if(e)e.value=v};set('#raidEnabled',s.enabled?'1':'0');set('#raidAccessMode',s.ownerOnlyTest===false?'PUBLIC':'OWNER_TEST');set('#raidTitle',s.title||'월드 레이드');set('#raidScheduleMode',s.scheduleMode||'ALWAYS');set('#raidOpenTime',s.openTime||'20:00');set('#raidCloseTime',s.closeTime||'21:00');set('#raidEntryCloseMinutes',s.entryCloseMinutes||0);set('#raidOwnerScheduleBypass',s.ownerScheduleBypass===false?'0':'1');set('#raidShowOpenCountdown',s.showOpenCountdown===false?'0':'1');document.querySelectorAll('.raidOpenDay').forEach(e=>e.checked=(s.openDays||[0,1,2,3,4,5,6]).includes(Number(e.value)));set('#raidMaxParticipants',s.maxParticipants||30);set('#raidMinParticipants',s.minParticipants||5);set('#raidLobbySeconds',s.lobbySeconds||60);set('#raidBattleSeconds',s.battleSeconds||120);set('#raidDeckHpMultiplier',s.deckHpMultiplier||12);set('#raidBossAttackPower',s.bossAttackPower||850);set('#raidBossAttackInterval',s.bossAttackIntervalMs||5000);set('#raidBossAttackVariance',s.bossAttackVariance??15);set('#raidEnrageEnabled',s.enrageEnabled===false?'0':'1');set('#raidEnrageHpPercent',s.enrageHpPercent||30);set('#raidEnrageMultiplier',s.enrageMultiplier||1.6);set('#raidShowBattleStage',s.showBattleStage===false?'0':'1');set('#raidShowParticipantHp',s.showParticipantHp===false?'0':'1');set('#raidDailyEntries',s.dailyEntries||1);set('#raidAutoStart',s.autoStartOnFull===false?'0':'1');set('#raidAttackInterval',s.attackIntervalMs||800);set('#raidDamageMultiplier',s.damageMultiplier||1);set('#raidCriticalEnabled',s.criticalEnabled===false?'0':'1');set('#raidCriticalChance',s.criticalChance??10);set('#raidCriticalMultiplier',s.criticalMultiplier||1.5);set('#raidRankingSize',s.rankingSize||10);set('#raidParticipationCoin',s.participationCoin||0);set('#raidClearCoin',s.clearCoin||0);set('#raidRewardShards',s.rewardShards||0);['ShowNicknames','ShowRepresentativeCard','ShowDamageLog','ShowPersonalDamage','ShowLiveRanking'].forEach(k=>{const e=$('#raid'+k);if(e)e.checked=s[k.charAt(0).toLowerCase()+k.slice(1)]!==false});renderRaidCurrent();renderRaidBosses()}
function raidSettingsDraft(){return {enabled:$('#raidEnabled').value==='1',ownerOnlyTest:true,title:$('#raidTitle').value.trim(),maxParticipants:Number($('#raidMaxParticipants').value),minParticipants:Number($('#raidMinParticipants').value),lobbySeconds:Number($('#raidLobbySeconds').value),battleSeconds:Number($('#raidBattleSeconds').value),deckHpMultiplier:Number($('#raidDeckHpMultiplier').value),bossAttackPower:Number($('#raidBossAttackPower').value),bossAttackIntervalMs:Number($('#raidBossAttackInterval').value),bossAttackVariance:Number($('#raidBossAttackVariance').value),enrageEnabled:$('#raidEnrageEnabled').value==='1',enrageHpPercent:Number($('#raidEnrageHpPercent').value),enrageMultiplier:Number($('#raidEnrageMultiplier').value),showBattleStage:$('#raidShowBattleStage').value==='1',showParticipantHp:$('#raidShowParticipantHp').value==='1',dailyEntries:Number($('#raidDailyEntries').value),autoStartOnFull:$('#raidAutoStart').value==='1',attackIntervalMs:Number($('#raidAttackInterval').value),damageMultiplier:Number($('#raidDamageMultiplier').value),criticalEnabled:$('#raidCriticalEnabled').value==='1',criticalChance:Number($('#raidCriticalChance').value),criticalMultiplier:Number($('#raidCriticalMultiplier').value),rankingSize:Number($('#raidRankingSize').value),participationCoin:Number($('#raidParticipationCoin').value),clearCoin:Number($('#raidClearCoin').value),rewardShards:Number($('#raidRewardShards').value),showNicknames:$('#raidShowNicknames').checked,showRepresentativeCard:$('#raidShowRepresentativeCard').checked,showDamageLog:$('#raidShowDamageLog').checked,showPersonalDamage:$('#raidShowPersonalDamage').checked,showLiveRanking:$('#raidShowLiveRanking').checked,scheduleMode:$('#raidScheduleMode').value,openTime:$('#raidOpenTime').value,closeTime:$('#raidCloseTime').value,entryCloseMinutes:Number($('#raidEntryCloseMinutes').value),ownerScheduleBypass:$('#raidOwnerScheduleBypass').value==='1',showOpenCountdown:$('#raidShowOpenCountdown').value==='1',openDays:[...document.querySelectorAll('.raidOpenDay:checked')].map(e=>Number(e.value))}}
async function saveRaidSettings(){const btn=$('#saveRaidSettingsBtn'),settings={...raidSettingsDraft(),ownerOnlyTest:false,userOpenEnabled:true};if(settings.minParticipants>settings.maxParticipants)return alert('최소 시작 인원은 최대 참가 인원보다 클 수 없습니다.');if(settings.scheduleMode==='SCHEDULED'&&!settings.openDays.length)return alert('레이드 개방 요일을 하나 이상 선택하세요.');if(btn){btn.disabled=true;btn.textContent='저장 중...'}try{const saved=await api('admin/raid',{method:'PATCH',body:JSON.stringify({settings})}),verified=await api('admin/raid');state.raidData=verified;if(JSON.stringify(saved.settings)!==JSON.stringify(verified.settings))throw Error('레이드 설정 저장 후 재조회 값이 일치하지 않습니다.');if(Number(verified.settings?.dailyEntries)!==Number(settings.dailyEntries))throw Error(`1일 참가 횟수 저장 검증에 실패했습니다. 요청 ${Number(settings.dailyEntries)}회 / 저장 ${Number(verified.settings?.dailyEntries||0)}회`);await loadRaidAdmin();alert(`레이드 설정 저장 완료 · 1일 참가 ${Number(verified.settings.dailyEntries)}회`)}finally{if(btn){btn.disabled=false;btn.textContent='레이드 설정 저장'}}}
async function addRaidBoss(){const p={action:'CREATE_BOSS',name:$('#raidBossName').value.trim(),image:$('#raidBossImage').value.trim(),maxHp:Number($('#raidBossMaxHp').value),defenseRate:Number($('#raidBossDefense').value),sortOrder:Number($('#raidBossSort').value),isActive:true,userOpenEnabled:$('#raidBossUserOpen')?.value==='1',openCost:Number($('#raidBossOpenCost')?.value||0)};if(!p.name)return alert('보스 이름을 입력하세요.');await api('admin/raid',{method:'POST',body:JSON.stringify(p)});$('#raidBossName').value='';await loadRaidAdmin();alert('레이드 보스가 추가되었습니다.')}
function renderRaidBosses(){const rows=state.raidData?.bosses||[];$('#raidBossList').innerHTML=rows.length?rows.map(b=>`<div class="panel raidBossRow" data-id="${b.id}"><div class="formgrid"><label class="field"><span>보스 이름</span><input class="rbName" value="${esc(b.name)}"></label><label class="field"><span>이미지</span><input class="rbImage" value="${esc(b.image||'')}"></label><label class="field"><span>최대 HP</span><input class="rbHp" type="number" value="${Number(b.maxHp)}"></label><label class="field"><span>방어 보정(%)</span><input class="rbDefense" type="number" value="${Number(b.defenseRate||0)}"></label><label class="field"><span>상태</span><select class="rbActive"><option value="1" ${b.isActive?'selected':''}>활성</option><option value="0" ${!b.isActive?'selected':''}>비활성</option></select></label><label class="field"><span>정렬</span><input class="rbSort" type="number" value="${Number(b.sortOrder||0)}"></label><label class="field"><span>유저 개방</span><select class="rbUserOpen"><option value="1" ${b.userOpenEnabled?'selected':''}>허용</option><option value="0" ${!b.userOpenEnabled?'selected':''}>차단</option></select></label><label class="field"><span>개방 비용(코인)</span><input class="rbOpenCost" type="number" min="0" value="${Number(b.openCost||0)}"></label></div><div class="bar"><button class="rbSave">저장</button><button class="rbStart" ${!b.isActive?'disabled':''}>이 보스로 레이드 시작</button></div></div>`).join(''):'<div class="panel muted">등록된 레이드 보스가 없습니다.</div>';document.querySelectorAll('.raidBossRow').forEach(row=>{row.querySelector('.rbSave').onclick=()=>saveRaidBoss(row);row.querySelector('.rbStart').onclick=()=>startRaid(Number(row.dataset.id))})}
async function saveRaidBoss(row){const boss={id:Number(row.dataset.id),name:row.querySelector('.rbName').value.trim(),image:row.querySelector('.rbImage').value.trim(),maxHp:Number(row.querySelector('.rbHp').value),defenseRate:Number(row.querySelector('.rbDefense').value),isActive:row.querySelector('.rbActive').value==='1',sortOrder:Number(row.querySelector('.rbSort').value),userOpenEnabled:row.querySelector('.rbUserOpen').value==='1',openCost:Number(row.querySelector('.rbOpenCost').value||0)};await api('admin/raid',{method:'PATCH',body:JSON.stringify({boss})});alert('보스 설정이 저장되었습니다.');await loadRaidAdmin()}
function renderRaidCurrent(){const c=state.raidData?.current;$('#raidCurrent').innerHTML=c?`<div class="raidCurrentCard"><b>${esc(c.bossName)} · ${esc(c.status)}</b><span>참가자 ${Number(c.participantCount||0)}명</span><span>HP ${Number(c.currentHp||0).toLocaleString()} / ${Number(c.maxHp||0).toLocaleString()}</span><span>시작 ${fmt(c.startsAt)} · 종료 ${fmt(c.endsAt)}</span><button id="endRaidBtn" class="danger">강제 종료</button></div>`:'<div class="inlineNotice">현재 진행 중인 레이드가 없습니다.</div>';const b=$('#endRaidBtn');if(b)b.onclick=()=>endRaid(c.id)}
async function startRaid(bossId){if(!confirm('선택한 보스로 레이드 대기방을 열까요?'))return;await api('admin/raid',{method:'POST',body:JSON.stringify({action:'START',bossId})});alert('레이드 대기방이 열렸습니다.');await loadRaidAdmin()}
async function endRaid(instanceId){if(!confirm('진행 중 레이드를 강제 종료할까요?'))return;await api('admin/raid',{method:'POST',body:JSON.stringify({action:'END',instanceId})});await loadRaidAdmin()}

async function loadUsers(){const q=$('#userSearch').value.trim(),verification=state.userVerificationFilter||'ALL';const d=await api('admin/users?q='+encodeURIComponent(q)+'&verification='+encodeURIComponent(verification));state.users=d.users;const verifyBadge=u=>{const st=u.verification_status||'UNVERIFIED';if(st==='VERIFIED')return `<span class="verifyBadge verified">2단계 인증 완료</span><small>${esc(u.wago_nickname||'')} · #${esc(u.wago_member_no||'')}</small>`;if(st==='PENDING'||st==='REVIEW')return `<span class="verifyBadge pending">인증 대기</span>`;if(st==='REJECTED')return `<span class="verifyBadge rejected">인증 해제/거절</span>`;return `<span class="verifyBadge unverified">미인증</span>`};$('#users').innerHTML=`<div class="tr head userRows"><b>닉네임 / 권한</b><b>2단계 인증</b><b>가입일</b><b>최근접속</b><b>보유코인</b><b>카드조각</b><b class="optional">카드</b><b class="optional">UR</b><b class="optional">SSR</b><b class="optional gradeHead limited">LIMITED</b><b class="optional gradeHead fur">FUR</b><b>상태</b><b></b></div>`+(d.users.length?d.users.map(u=>`<div class="tr userRows"><b>${esc(u.nickname)}<small>${esc(u.role)}</small></b><span>${verifyBadge(u)}</span><span>${fmt(u.created_at)}</span><span>${fmt(u.last_login_at)}</span><span>${Number(u.coin).toLocaleString()}</span><span>${Number(u.card_shards||0).toLocaleString()}</span><span class="optional">${u.card_count||0}</span><span class="optional">${u.ur_count||0}</span><span class="optional">${u.ssr_count||0}</span><span class="optional gradeCount limited">${u.limited_count||0}</span><span class="optional gradeCount fur">${u.fur_count||0}</span><span class="status-${u.status}">${u.status==='ACTIVE'?'정상':'이용정지'}</span><button data-user="${u.id}">상세 관리</button></div>`).join(''):'<div class="panel muted">검색된 유저가 없습니다.</div>');document.querySelectorAll('[data-user]').forEach(b=>b.onclick=()=>openUser(Number(b.dataset.user)))}
function openUser(id){const u=state.users.find(x=>x.id===id);$('#selectedUserId').value=id;$('#userDialogTitle').textContent=u.nickname+' 관리';$('#userDetail').innerHTML=`<div class="panel"><p>권한 <b>${esc(u.role)}</b> · 상태 <b class="status-${u.status}">${u.status==='ACTIVE'?'정상 이용':'이용정지'}</b></p><p>보유코인 <b>${Number(u.coin).toLocaleString()}</b> · 카드 조각 <b>${Number(u.card_shards||0).toLocaleString()}</b> · 카드 ${u.card_count||0} · UR ${u.ur_count||0} · SSR ${u.ssr_count||0}</p><small>가입 ${fmt(u.created_at)} · 최근접속 ${fmt(u.last_login_at)}</small></div>`;let inventoryBlock=$('#inventoryGrantBlock');if(!inventoryBlock){const accountBlock=[...document.querySelectorAll('#userDialog .actionBlock')].find(x=>x.querySelector('h3')?.textContent.includes('계정 관리'));accountBlock?.insertAdjacentHTML('beforebegin',`<div class="actionBlock" id="inventoryGrantBlock"><h3>보상 큐브 지급</h3><div class="two"><select id="inventoryItemCode"><option value="NORMAL_CUBE">일반 큐브 · C~SR</option><option value="ADVANCED_CUBE">고급 큐브 · HR~SSR</option><option value="PREMIUM_CUBE">프리미엄 큐브 · MA~LIMITED</option></select><input id="inventoryItemAmount" type="number" min="1" max="9999" value="1"></div><input id="inventoryItemReason" value="콘텐츠 보상 테스트 지급" placeholder="지급 사유"><button type="button" id="inventoryGrantBtn">보상 큐브 지급</button></div>`);inventoryBlock=$('#inventoryGrantBlock');if(inventoryBlock)$('#inventoryGrantBtn').onclick=()=>userAction('INVENTORY')}$('#userDialog').showModal()}
async function userAction(action){const userId=Number($('#selectedUserId').value),p={userId,action};if(action==='COIN'){p.amount=Number($('#coinAmount').value);p.reason=$('#coinReason').value.trim();if(!p.amount)return alert('지급 또는 회수할 코인을 입력하세요.')}if(action==='SHARDS'){p.amount=Number($('#shardAmount').value);p.reason=$('#shardReason').value.trim();if(!p.amount)return alert('지급 또는 회수할 카드 조각을 입력하세요.')}if(action==='INVENTORY'){p.itemCode=$('#inventoryItemCode').value;p.amount=Number($('#inventoryItemAmount').value);p.reason=$('#inventoryItemReason').value.trim();if(!p.itemCode||!Number.isInteger(p.amount)||p.amount<1)return alert('지급 아이템과 수량을 확인하세요.')}if(action==='BAN'){p.days=$('#banDays').value;p.reason=$('#banReason').value.trim();if(!p.reason)return alert('이용정지 사유를 입력하세요.')}const names={COIN:'코인 조정',SHARDS:'카드 조각 조정',INVENTORY:'인벤토리 아이템 지급',CARDS_RESET:'카드 초기화',ATTENDANCE_RESET:'출석 초기화',ACCOUNT_RESET:'계정 초기화',BAN:'이용정지',UNBAN:'이용해제'};if(!confirm(`${names[action]} 작업을 실행할까요?`))return;await api('admin/users/action',{method:'POST',body:JSON.stringify(p)});$('#userDialog').close();await loadUsers();alert(`${names[action]} 처리가 완료되었습니다.`)}
async function resetKey(){const userId=Number($('#selectedUserId').value);if(!confirm('기존 개인키와 로그인 세션이 즉시 무효화됩니다.\n새 개인키를 발급할까요?'))return;const d=await api('admin/users/private-key-reset',{method:'POST',body:JSON.stringify({userId})});prompt('새 개인키입니다. 이 창을 닫기 전에 복사하세요.',d.privateKey)}
async function loadCoupons(){const d=await api('admin/coupons');$('#coupons').innerHTML=`<div class="tr head"><b>쿠폰 코드</b><b>보상</b><b>사용량</b><b>시작</b><b>종료</b><b class="optional">1인 제한</b><b>상태</b><b></b></div>`+(d.coupons.length?d.coupons.map(c=>`<div class="tr"><div class="couponCode"><b>${esc(c.code)}</b><button class="ghost copyCoupon" data-code="${esc(c.code)}">복사</button></div><span>${Number(c.reward_coin).toLocaleString()} 코인</span><span>${c.used_count} / ${c.max_uses}</span><span>${fmt(c.starts_at)}</span><span>${fmt(c.ends_at)}</span><span class="optional">계정당 1회</span><span><i class="statusPill ${c.is_active?'':'off'}">${c.is_active?'사용 가능':'중지됨'}</i></span><button data-coupon="${c.id}" data-active="${c.is_active}">${c.is_active?'비활성':'재활성'}</button></div>`).join(''):'<div class="panel muted">발급된 쿠폰이 없습니다.</div>');document.querySelectorAll('[data-coupon]').forEach(b=>b.onclick=()=>toggleCoupon(b));document.querySelectorAll('.copyCoupon').forEach(b=>b.onclick=()=>copyCoupon(b.dataset.code,b))}
async function copyCoupon(code,btn){try{await navigator.clipboard.writeText(code);const old=btn.textContent;btn.textContent='복사됨';setTimeout(()=>btn.textContent=old,1000)}catch{prompt('쿠폰 코드를 복사하세요.',code)}}
async function createCoupon(){const p={code:$('#couponCode').value.trim(),rewardCoin:Number($('#couponReward').value),maxUses:Number($('#couponMax').value),startsAt:toSql($('#couponStart').value),endsAt:toSql($('#couponEnd').value)};if(!p.code)return alert('쿠폰 코드를 입력하세요.');if(!p.startsAt||!p.endsAt)return alert('쿠폰 사용 시작과 종료 시간을 모두 입력하세요.');if(new Date($('#couponEnd').value)<=new Date($('#couponStart').value))return alert('종료 시간은 시작 시간보다 늦어야 합니다.');const btn=$('#createCouponBtn');setBusy(btn,true,'발급 중...');try{await api('admin/coupons',{method:'POST',body:JSON.stringify(p)});$('#couponCode').value='';await loadCoupons();alert('공용 쿠폰이 발급되었습니다.\n모든 유저가 계정당 한 번 사용할 수 있습니다.')}finally{setBusy(btn,false)}}
async function toggleCoupon(b){const enabling=b.dataset.active!=='1';if(!confirm(enabling?'이 쿠폰을 다시 사용할 수 있게 할까요?':'이 쿠폰의 사용을 즉시 중지할까요?'))return;await api('admin/coupons',{method:'PATCH',body:JSON.stringify({id:Number(b.dataset.coupon),isActive:enabling})});await loadCoupons()}
async function loadLogs(){const d=await api('admin/logs');$('#logs').innerHTML=d.logs.length?d.logs.map(l=>`<div class="panel logRow"><span>${fmt(l.created_at)}</span><b>${esc(l.admin_nickname||'알 수 없음')}<small>${esc(l.admin_role||'')}</small></b><span>${actionName(l.action_type)}<small>${esc(l.target_type)} #${esc(l.target_id)}</small></span><div class="detail">${logSummary(l)}${l.after_data?`<code>${esc(l.after_data)}</code>`:''}</div></div>`).join(''):'<div class="panel muted">기록된 관리자 작업이 없습니다.</div>'}
function actionName(v){return ({COIN:'코인 조정',SHARDS:'카드 조각 조정',CARDS_RESET:'카드 초기화',ATTENDANCE_RESET:'출석 초기화',ACCOUNT_RESET:'계정 초기화',BAN:'이용정지',UNBAN:'이용해제',PRIVATE_KEY_RESET:'개인키 재발급',COUPON_CREATE:'쿠폰 발급',COUPON_UPDATE:'쿠폰 변경',SETTINGS_UPDATE:'설정 변경',CARD_UPDATE:'카드 수정',CARD_CREATE:'카드 추가',CARD_DELETE:'카드 삭제',PACK_RATE_UPDATE:'카드팩 확률 변경',BREAKTHROUGH_SETTINGS_UPDATE:'돌파 확률 변경',CRITICAL_SETTINGS_UPDATE:'크리티컬 설정 변경',MAINTENANCE_START:'서버 점검 시작',MAINTENANCE_END:'서버 점검 종료'})[v]||v}
function logSummary(l){return `${esc(l.admin_nickname||'관리자')} 계정이 ${esc(l.target_type||'대상')}에 ${esc(actionName(l.action_type))} 작업을 실행했습니다.`}
function localDateTime(v){if(!v)return'';const raw=String(v).replace(' ','T');return raw.slice(0,16)}
function renderMaintenanceState(){const on=$('#maintenance').value==='1';const badge=$('#maintenanceState');badge.textContent=on?'점검 진행 중':'정상 운영 중';badge.classList.toggle('off',on)}
async function loadSettings(){
  const notice=$('#breakthroughLoadState');
  if(notice){notice.textContent='설정 데이터를 불러오는 중입니다.';notice.className='inlineNotice'}
  const d=await api('admin/settings'),x=d.settings||{},ac=d.attendance||{enabled:true,rewards:[1000,1200,1400,1600,1800,2000,3000]};if($('#attendanceEnabled'))$('#attendanceEnabled').value=ac.enabled===false?'0':'1';for(let i=1;i<=7;i++){const el=$('#attendanceReward'+i);if(el)el.value=Number(ac.rewards?.[i-1]||0);}renderCubeSettings(d.cubes||{});renderCubeBoostSettings(d.cubeBoost||{});
  $('#newUserCoin').value=x.new_user_coin||5000;$('#siteNotice').value=x.site_notice||'';$('#criticalEnabled').value=x.critical_enabled??'1';$('#criticalMinTaps').value=x.critical_min_taps||5;$('#criticalChance').value=x.critical_chance||3;$('#criticalBonus').value=x.critical_bonus||10;$('#criticalEffects').value=x.critical_effects??'1';$('#maintenance').value=x.maintenance_mode||'0';$('#maintenanceTitle').value=x.maintenance_title||'씨켓몬 서버 점검 중';$('#maintenanceMessage').value=x.maintenance_message||'안정적인 서비스 제공을 위해 점검을 진행하고 있습니다.';$('#maintenanceStart').value=localDateTime(x.maintenance_start_at);$('#maintenanceEnd').value=localDateTime(x.maintenance_end_at);$('#maintenanceTestUsers').value=x.maintenance_test_users||'';$('#newUserCoin').disabled=state.role!=='OWNER';$('#siteNotice').disabled=state.role!=='OWNER';renderMaintenanceState();
  try{
    const b=await api('admin/breakthrough-settings');
    state.breakthroughData=b.config;
    state.breakthroughGrade=$('#breakthroughGrade').value||'SR';
    renderBreakthroughFields();
    if(notice){notice.textContent='D1 돌파 설정을 정상적으로 불러왔습니다.';notice.className='inlineNotice ok'}
  }catch(e){
    state.breakthroughData=null;
    $('#breakthroughFields').innerHTML='';
    if(notice){notice.textContent='돌파 설정 API 오류: '+e.message;notice.className='inlineNotice error'}
    throw e;
  }
}
function renderCubeSettings(cubes){let panel=$('#cubeSettingsPanel');if(!panel){document.querySelector('#view-settings .breakthroughSettings')?.insertAdjacentHTML('beforebegin',`<div class="panel cubeSettings" id="cubeSettingsPanel"><div class="maintenanceHead"><div><small>REWARD CUBE CONTROL</small><h2>보상 큐브 등급 설정</h2><p>드랍·이벤트 큐브의 카드 등급 확률입니다. 큐브별 합계는 반드시 100%여야 합니다.</p></div></div><div id="cubeSettingsFields" class="cubeSettingsFields"></div><button id="saveCubeSettingsBtn" type="button">큐브 확률 저장</button></div>`);panel=$('#cubeSettingsPanel');$('#saveCubeSettingsBtn').onclick=saveCubeSettings}const names={NORMAL_CUBE:'일반 큐브 · C~SR',ADVANCED_CUBE:'고급 큐브 · HR~SSR',PREMIUM_CUBE:'프리미엄 큐브 · MA~LIMITED'},defaults={NORMAL_CUBE:{C:45,U:30,R:18,SR:7},ADVANCED_CUBE:{HR:55,UR:30,SSR:15},PREMIUM_CUBE:{MA:70,FUR:20,LIMITED:10}};$('#cubeSettingsFields').innerHTML=Object.entries(defaults).map(([code,grades])=>`<section class="cubeSettingGroup" data-cube="${code}"><div><b>${names[code]}</b><span class="cubeRateTotal">합계 100%</span></div><div class="formgrid">${Object.keys(grades).map(g=>`<label class="field"><span>${g} 확률 (%)</span><input class="cubeRateInput" data-grade="${g}" type="number" min="0" max="100" step="0.01" value="${Number(cubes?.[code]?.[g]??grades[g])}"></label>`).join('')}</div></section>`).join('');panel.querySelectorAll('.cubeRateInput').forEach(x=>x.oninput=updateCubeTotals);updateCubeTotals()}
function updateCubeTotals(){document.querySelectorAll('.cubeSettingGroup').forEach(group=>{const total=[...group.querySelectorAll('.cubeRateInput')].reduce((n,x)=>n+Number(x.value||0),0),label=group.querySelector('.cubeRateTotal');label.textContent=`합계 ${total.toFixed(2)}%`;label.classList.toggle('error',Math.abs(total-100)>.001)})}
async function saveCubeSettings(){const cubes={};for(const group of document.querySelectorAll('.cubeSettingGroup')){cubes[group.dataset.cube]={};group.querySelectorAll('.cubeRateInput').forEach(x=>cubes[group.dataset.cube][x.dataset.grade]=Number(x.value||0));const total=Object.values(cubes[group.dataset.cube]).reduce((a,b)=>a+b,0);if(Math.abs(total-100)>.001)return alert(`${group.querySelector('b').textContent} 확률 합계를 100%로 맞춰주세요.`)}await api('admin/settings',{method:'POST',body:JSON.stringify({cubes})});alert('큐브별 등급 확률이 저장되었습니다.');await loadSettings()}
function renderCubeBoostSettings(cfg){
  const d={enabled:true,targetHighGradeCount:2,zeroCountMultiplier:1.5,oneCountMultiplier:1.25,pveEnabled:true,pvpEnabled:true,excludeAdmins:true,pityEnabled:true,pityStartWins:30,pityIncrementRate:0.05,pityMaxBonusRate:2,...cfg};
  let panel=$('#cubeBoostSettingsPanel');
  if(!panel){$('#cubeSettingsPanel')?.insertAdjacentHTML('afterend',`<div class="panel cubeSettings" id="cubeBoostSettingsPanel"><div class="maintenanceHead"><div><small>PREMIUM CUBE SUPPORT</small><h2>고등급 카드 부족 유저 보정</h2><p>MA·LIMITED·FUR 보유 수량이 기준보다 적은 유저에게 프리미엄 큐브 확률만 보정합니다. 서버에서만 판정되며 한 전투 최대 1개 원칙은 유지됩니다.</p></div></div><div id="cubeBoostSettingsFields" class="formgrid"></div><div class="inlineNotice">0개 보유자는 1.5배, 1개 보유자는 1.25배가 기본값입니다. 연속 미획득 보정은 프리미엄 큐브 획득 시 초기화됩니다.</div><button id="saveCubeBoostSettingsBtn" type="button">부족 유저 보정 저장</button></div>`);panel=$('#cubeBoostSettingsPanel');$('#saveCubeBoostSettingsBtn').onclick=saveCubeBoostSettings}
  $('#cubeBoostSettingsFields').innerHTML=`
    <label class="field"><span>보정 기능</span><select id="cubeBoostEnabled"><option value="1" ${d.enabled?'selected':''}>사용</option><option value="0" ${!d.enabled?'selected':''}>중지</option></select></label>
    <label class="field"><span>보정 종료 보유량</span><input id="cubeBoostTarget" type="number" min="1" max="20" step="1" value="${Number(d.targetHighGradeCount)}"><small>MA+LIMITED+FUR 총 수량</small></label>
    <label class="field"><span>0개 보유 배율</span><input id="cubeBoostZero" type="number" min="1" max="10" step="0.01" value="${Number(d.zeroCountMultiplier)}"></label>
    <label class="field"><span>1개 보유 배율</span><input id="cubeBoostOne" type="number" min="1" max="10" step="0.01" value="${Number(d.oneCountMultiplier)}"></label>
    <label class="field"><span>PVE 적용</span><select id="cubeBoostPve"><option value="1" ${d.pveEnabled?'selected':''}>적용</option><option value="0" ${!d.pveEnabled?'selected':''}>미적용</option></select></label>
    <label class="field"><span>PVP 적용</span><select id="cubeBoostPvp"><option value="1" ${d.pvpEnabled?'selected':''}>적용</option><option value="0" ${!d.pvpEnabled?'selected':''}>미적용</option></select></label>
    <label class="field"><span>OWNER·ADMIN 제외</span><select id="cubeBoostExcludeAdmins"><option value="1" ${d.excludeAdmins?'selected':''}>제외</option><option value="0" ${!d.excludeAdmins?'selected':''}>포함</option></select></label>
    <label class="field"><span>연속 미획득 보정</span><select id="cubeBoostPity"><option value="1" ${d.pityEnabled?'selected':''}>사용</option><option value="0" ${!d.pityEnabled?'selected':''}>중지</option></select></label>
    <label class="field"><span>보정 시작 승수</span><input id="cubeBoostPityStart" type="number" min="1" max="10000" step="1" value="${Number(d.pityStartWins)}"></label>
    <label class="field"><span>승리당 추가 확률</span><input id="cubeBoostPityStep" type="number" min="0" max="10" step="0.01" value="${Number(d.pityIncrementRate)}"><small>%p</small></label>
    <label class="field"><span>최대 추가 확률</span><input id="cubeBoostPityMax" type="number" min="0" max="100" step="0.01" value="${Number(d.pityMaxBonusRate)}"><small>%p</small></label>`;
}
async function saveCubeBoostSettings(){const cubeBoost={enabled:$('#cubeBoostEnabled').value==='1',targetHighGradeCount:Number($('#cubeBoostTarget').value),zeroCountMultiplier:Number($('#cubeBoostZero').value),oneCountMultiplier:Number($('#cubeBoostOne').value),pveEnabled:$('#cubeBoostPve').value==='1',pvpEnabled:$('#cubeBoostPvp').value==='1',excludeAdmins:$('#cubeBoostExcludeAdmins').value==='1',pityEnabled:$('#cubeBoostPity').value==='1',pityStartWins:Number($('#cubeBoostPityStart').value),pityIncrementRate:Number($('#cubeBoostPityStep').value),pityMaxBonusRate:Number($('#cubeBoostPityMax').value)};if(cubeBoost.zeroCountMultiplier<1||cubeBoost.oneCountMultiplier<1)return alert('보정 배율은 1 이상이어야 합니다.');const btn=$('#saveCubeBoostSettingsBtn');setBusy(btn,true,'저장 중...');try{await api('admin/settings',{method:'POST',body:JSON.stringify({cubeBoost})});const verified=await api('admin/settings');renderCubeBoostSettings(verified.cubeBoost||cubeBoost);alert('고등급 카드 부족 유저 보정 설정이 저장되었습니다.')}finally{setBusy(btn,false)}}
function renderBreakthroughFields(){if(!state.breakthroughData)return;const grade=$('#breakthroughGrade').value,rows=state.breakthroughData[grade]||[];$('#breakthroughFields').innerHTML=rows.map((x,i)=>`<div class="btSettingRow"><b>★${i} → ★${i+1}</b><label class="field"><span>필요 조각</span><input class="btCost" data-level="${i}" type="number" min="1" step="1" value="${x.cost}"></label><label class="field"><span>성공 확률 (%)</span><input class="btRate" data-level="${i}" type="number" min="0" max="100" step="0.0001" value="${x.rate}"></label></div>`).join('')}
function captureBreakthroughGrade(grade=state.breakthroughGrade){if(!state.breakthroughData||!grade)return;document.querySelectorAll('.btSettingRow').forEach((row,i)=>{state.breakthroughData[grade][i]={cost:Number(row.querySelector('.btCost').value),rate:Number(row.querySelector('.btRate').value)}})}
async function saveBreakthroughSettings(){captureBreakthroughGrade();const btn=$('#saveBreakthroughBtn');setBusy(btn,true,'저장 중...');try{const d=await api('admin/breakthrough-settings',{method:'PATCH',body:JSON.stringify({config:state.breakthroughData})});state.breakthroughData=d.config||state.breakthroughData;const notice=$('#breakthroughLoadState');if(notice){notice.textContent='저장 완료: D1에 돌파 설정이 반영되었습니다.';notice.className='inlineNotice ok'}alert('등급별 돌파 비용과 성공 확률이 저장되었습니다.')}finally{setBusy(btn,false)}}
function resetBreakthroughDefaults(){if(!confirm('현재 입력값을 기본 설정으로 되돌릴까요? 저장 버튼을 눌러야 실제 반영됩니다.'))return;const costs=[50,100,200,350,550,800,1100,1450,1850,2300],rates=[100,100,100,80,65,50,35,25,15,8];for(const g of ['SR','HR','UR','SSR','MA','FUR'])state.breakthroughData[g]=costs.map((cost,i)=>({cost,rate:rates[i]}));renderBreakthroughFields()}
async function saveSettings(){const mode=$('#maintenance').value;if(mode==='1'&&!confirm('서버 점검을 시작하시겠습니까?\n\n일반 유저의 로그인 상태는 유지되고 게임 기능만 차단됩니다.\n등록한 테스트 계정과 OWNER·ADMIN은 계속 이용할 수 있습니다.'))return;const payload={maintenance_mode:mode,maintenance_title:$('#maintenanceTitle').value.trim(),maintenance_message:$('#maintenanceMessage').value.trim(),maintenance_start_at:toSql($('#maintenanceStart').value),maintenance_end_at:toSql($('#maintenanceEnd').value),maintenance_test_users:$('#maintenanceTestUsers').value.split(',').map(x=>x.trim()).filter(Boolean).join(','),critical_enabled:$('#criticalEnabled').value,critical_min_taps:Math.max(1,Number($('#criticalMinTaps').value)||5),critical_chance:Math.max(0,Math.min(100,Number($('#criticalChance').value)||0)),critical_bonus:Math.max(0,Math.min(100,Number($('#criticalBonus').value)||0)),critical_effects:$('#criticalEffects').value,attendance:{enabled:$('#attendanceEnabled')?$('#attendanceEnabled').value==='1':true,rewards:Array.from({length:7},(_,i)=>{const el=$('#attendanceReward'+(i+1));return Math.max(0,Number(el?.value??[1000,1200,1400,1600,1800,2000,3000][i])||0)})}};if(state.role==='OWNER'){payload.new_user_coin=$('#newUserCoin').value;payload.site_notice=$('#siteNotice').value}await api('admin/settings',{method:'POST',body:JSON.stringify(payload)});renderMaintenanceState();alert(mode==='1'?'서버 점검 모드가 시작되었습니다. 로그인 상태는 유지되고 게임 기능만 차단됩니다.':'서버 점검이 종료되어 정상 운영으로 전환되었습니다.')}


function ultimateRuleTemplate(x={},i=0){const grades=['C','U','R','SR','HR','UR','SSR','MA','FUR'];return `<div class="panel ultimateRuleRow" data-index="${i}"><div class="maintenanceHead"><div><b>궁극기 조건 ${i+1}</b><small>조건 충족 후 발동 확률 판정에 성공하면 PVE에서 컷신 후 조건 충족 카드 1장 기준의 궁극기 타격 데미지가 적용됩니다.</small></div><button type="button" class="ghost removeUltimateRule">삭제</button></div><div class="formgrid"><label class="field"><span>사용 여부</span><select class="uEnabled"><option value="1" ${x.enabled===false?'':'selected'}>사용</option><option value="0" ${x.enabled===false?'selected':''}>중지</option></select></label><label class="field"><span>궁극기 이름</span><input class="uName" maxlength="40" value="${esc(x.name||'SSR AWAKENING')}"></label><label class="field"><span>대상 등급</span><select class="uGrade">${grades.map(g=>`<option value="${g}" ${String(x.requiredGrade||'SSR')===g?'selected':''}>${g}</option>`).join('')}</select></label><label class="field"><span>최소 돌파</span><input class="uBreakthrough" type="number" min="0" max="20" value="${Number(x.minBreakthrough??5)}"></label><label class="field"><span>필요 카드 수</span><input class="uCount" type="number" min="1" max="5" value="${Number(x.requiredCount??1)}"></label><label class="field"><span>발동 확률 (%)</span><input class="uChance" type="number" min="0" max="100" step="0.01" value="${Number(x.activationChance??100)}"><small>100 = 조건 충족 시 항상 발동</small></label><label class="field wide"><span>GIF / WebM / MP4 경로</span><input class="uMedia" value="${esc(x.mediaUrl||'/assets/effects/SKILL.gif')}" placeholder="/assets/effects/SKILL.gif"></label><label class="field"><span>재생 시간(ms)</span><input class="uDuration" type="number" min="800" max="30000" value="${Number(x.durationMs??3000)}"></label><label class="field"><span>궁극기 계수 (%)</span><input class="uCoefficient" type="number" min="0" max="100000" step="0.01" value="${Number(x.coefficientPercent??x.damageValue??500)}"><small>조건 충족 카드 중 공격력이 가장 높은 카드 1장 × 계수</small></label></div></div>`}
function renderUltimateRules(rules=[]){const box=$('#battleUltimateRules');if(!box)return;box.innerHTML=(rules.length?rules:[{enabled:true,name:'SSR AWAKENING',requiredGrade:'SSR',minBreakthrough:5,requiredCount:1,activationChance:100,mediaUrl:'/assets/effects/SKILL.gif',durationMs:3000,coefficientPercent:500}]).map(ultimateRuleTemplate).join('');box.querySelectorAll('.removeUltimateRule').forEach(b=>b.onclick=()=>{b.closest('.ultimateRuleRow').remove();[...box.querySelectorAll('.ultimateRuleRow')].forEach((r,i)=>{r.dataset.index=i;r.querySelector('.maintenanceHead b').textContent=`궁극기 조건 ${i+1}`})})}
function collectUltimateRules(){return [...document.querySelectorAll('.ultimateRuleRow')].map(r=>({enabled:r.querySelector('.uEnabled').value==='1',name:r.querySelector('.uName').value.trim()||'ULTIMATE',requiredGrade:r.querySelector('.uGrade').value,minBreakthrough:Number(r.querySelector('.uBreakthrough').value),requiredCount:Number(r.querySelector('.uCount').value),activationChance:Number(r.querySelector('.uChance').value),mediaUrl:r.querySelector('.uMedia').value.trim().replace(/\\/g,'/'),durationMs:Number(r.querySelector('.uDuration').value),coefficientPercent:Number(r.querySelector('.uCoefficient').value)}))}
async function loadUltimateAdmin(){const d=await api('admin/battle');state.battleData=d;renderUltimateRules(d.settings.ultimateRules||[])}
async function loadBattleAdmin(){const d=await api('admin/battle');state.battleData=d;$('#battleEnabled').value=d.settings.enabled?'1':'0';const cd=d.settings.cardDrop||{};$('#battleCardDropEnabled').value=cd.enabled===false?'0':'1';$('#battleCardDropDefaultRate').value=cd.defaultRate??3;const gradeRates=cd.gradeRates||{C:40,U:25,R:15,SR:10,HR:6,UR:3,SSR:1,MA:0,FUR:0};$('#battleCardDropGradeRates').innerHTML=Object.entries(gradeRates).map(([g,v])=>`<label class="field"><span>${g} 드롭 확률 (%)</span><input class="battleDropGradeInput" data-grade="${g}" type="number" min="0" max="100" step="0.01" value="${v}"></label>`).join('');const updateDropTotal=()=>{const total=[...document.querySelectorAll('.battleDropGradeInput')].reduce((a,x)=>a+Number(x.value||0),0);const el=$('#battleCardDropRateTotal');el.textContent=`등급 확률 합계: ${total.toFixed(2)}%`;el.classList.toggle('error',Math.abs(total-100)>0.001)};document.querySelectorAll('.battleDropGradeInput').forEach(x=>x.addEventListener('input',updateDropTotal));updateDropTotal();renderUltimateRules(d.settings.ultimateRules||[]);const e=d.settings.energy||{};$('#battleEnergyEnabled').value=e.enabled===false?'0':'1';$('#battleEnergyMax').value=e.maxEnergy??10;$('#battleEnergyDaily').value=e.dailyRestore??10;$('#battleEnergyMinutes').value=e.rechargeMinutes??15;$('#battleEnergyCost').value=e.costPerBattle??1;$('#battleAdminUnlimited').value=e.adminUnlimited===false?'0':'1';$('#battleTestUnlimited').value=e.testUnlimited===false?'0':'1';$('#battleGradePower').innerHTML=Object.entries(d.settings.powerByGrade).map(([g,v])=>`<label class="field"><span>${g} 기본 전투력</span><input class="battleGradeInput" data-grade="${g}" type="number" min="0" value="${v}"></label>`).join('');$('#battleBreakthroughPower').innerHTML=d.settings.breakthroughBonus.map((v,i)=>`<label class="field"><span>★${i} 보너스 (%)</span><input class="battleBtInput" data-level="${i}" type="number" min="0" value="${v}"></label>`).join('');renderMonsterAdmin()}
function renderMonsterAdmin(){const rows=state.battleData?.monsters||[];$('#monsterAdminList').innerHTML=rows.map(m=>`<div class="panel monsterAdminRow" data-mid="${m.id}"><input class="mName" value="${esc(m.name)}"><input class="mImage" value="${esc(m.image||'')}" placeholder="이미지 경로"><input class="mPower" type="number" value="${m.battlePower}"><input class="mReward" type="number" value="${m.rewardCoin}"><select class="mBoss"><option value="0" ${m.isBoss?'':'selected'}>일반</option><option value="1" ${m.isBoss?'selected':''}>보스</option></select><select class="mActive"><option value="1" ${m.isActive?'selected':''}>사용</option><option value="0" ${m.isActive?'':'selected'}>중지</option></select><input class="mSort" type="number" value="${m.sortOrder||0}"><button class="saveMonster">저장</button><button class="ghost stopMonster">중지</button></div>`).join('');document.querySelectorAll('.saveMonster').forEach(b=>b.onclick=()=>saveMonster(b.closest('.monsterAdminRow')));document.querySelectorAll('.stopMonster').forEach(b=>b.onclick=()=>stopMonster(b.closest('.monsterAdminRow')))}
async function saveBattleAdminSettings(){const powerByGrade={},breakthroughBonus=[],gradeRates={};document.querySelectorAll('.battleGradeInput').forEach(x=>powerByGrade[x.dataset.grade]=Number(x.value));document.querySelectorAll('.battleBtInput').forEach(x=>breakthroughBonus[Number(x.dataset.level)]=Number(x.value));document.querySelectorAll('.battleDropGradeInput').forEach(x=>gradeRates[x.dataset.grade]=Number(x.value));const total=Object.values(gradeRates).reduce((a,b)=>a+Number(b||0),0);if(Math.abs(total-100)>0.001)return alert(`카드 드롭 등급 확률 합계를 100%로 맞춰주세요. 현재 ${total.toFixed(2)}%입니다.`);const ultimateRules=state.battleData?.settings?.ultimateRules||[];await api('admin/battle',{method:'PATCH',body:JSON.stringify({settings:{enabled:$('#battleEnabled').value==='1',powerByGrade,breakthroughBonus,cardDrop:{enabled:$('#battleCardDropEnabled').value==='1',defaultRate:Number($('#battleCardDropDefaultRate').value),gradeRates},energy:state.battleData?.settings?.energy,ultimateRules}})});alert('전투력·카드 드롭 설정이 저장되었습니다.');await loadBattleAdmin()}

async function saveUltimateSettings(){const btn=$('#saveUltimateSettingsBtn');const ultimateRules=collectUltimateRules();for(const [i,u] of ultimateRules.entries()){if(!Number.isFinite(u.activationChance)||u.activationChance<0||u.activationChance>100)return alert(`궁극기 조건 ${i+1}의 발동 확률을 0~100으로 입력하세요.`);if(!Number.isFinite(u.coefficientPercent)||u.coefficientPercent<0||u.coefficientPercent>100000)return alert(`궁극기 조건 ${i+1}의 계수를 0~100000으로 입력하세요.`);if(!u.mediaUrl)u.mediaUrl='/assets/effects/SKILL.gif';if(!u.mediaUrl.startsWith('/')&&!/^https?:\/\//i.test(u.mediaUrl))u.mediaUrl='/'+u.mediaUrl.replace(/^\/+/, '');}setBusy(btn,true,'저장·검증 중...');try{const saved=await api('admin/battle',{method:'PATCH',body:JSON.stringify({ultimateRules})});const verified=await api('admin/battle');const actual=verified.settings?.ultimateRules||[];if(JSON.stringify(actual)!==JSON.stringify(saved.ultimateRules||ultimateRules))throw Error('D1 저장 후 재조회 값이 일치하지 않습니다.');state.battleData=verified;renderUltimateRules(actual);alert('궁극기 설정이 D1에 저장되었고 재조회 검증까지 완료되었습니다.')}finally{setBusy(btn,false)}}
async function saveBattleEnergySettings(){const current=state.battleData?.settings||{},energy={enabled:$('#battleEnergyEnabled').value==='1',maxEnergy:Number($('#battleEnergyMax').value),dailyRestore:Number($('#battleEnergyDaily').value),rechargeMinutes:Number($('#battleEnergyMinutes').value),costPerBattle:Number($('#battleEnergyCost').value),adminUnlimited:$('#battleAdminUnlimited').value==='1',testUnlimited:$('#battleTestUnlimited').value==='1'};await api('admin/battle',{method:'PATCH',body:JSON.stringify({settings:{...current,energy}})});alert('전투 횟수 설정이 저장되었습니다.');await loadBattleAdmin()}

function monsterPayload(row){return {id:Number(row?.dataset.mid||0),name:row?row.querySelector('.mName').value:$('#monsterName').value,image:row?row.querySelector('.mImage').value:$('#monsterImage').value,battlePower:Number(row?row.querySelector('.mPower').value:$('#monsterPower').value),rewardCoin:Number(row?row.querySelector('.mReward').value:$('#monsterReward').value),isBoss:(row?row.querySelector('.mBoss').value:$('#monsterBoss').value)==='1',isActive:row?row.querySelector('.mActive').value==='1':true,sortOrder:Number(row?row.querySelector('.mSort').value:$('#monsterSort').value)}}
