async function loadTierAdmin(){const d=await api('admin/tiers');state.tierData=d;const p=d.settings.pvp||{};$('#pvpEnabled').value=p.enabled===false?'0':'1';$('#pvpTierStatus').value=p.status||'진행 중';$('#pvpSeasonEnglishTitle').value=p.seasonTitle||'ASYNC PVP SEASON';$('#pvpSeasonName').value=p.seasonName||'시즌 1';$('#pvpSeasonDescription').value=p.seasonDescription||'저장한 PvP 덱으로 비동기 대전을 진행합니다.';$('#pvpSeasonStart').value=localDateTime(p.startsAt);$('#pvpSeasonEnd').value=localDateTime(p.endsAt);$('#pvpInitialScore').value=Number(p.initialScore??1000);$('#pvpWinScore').value=Number(p.winScore??24);$('#pvpLoseScore').value=Number(p.loseScore??16);if($('#pvpWinCoin'))$('#pvpWinCoin').value=Number(p.winCoin??50);if($('#pvpLoseCoin'))$('#pvpLoseCoin').value=Number(p.loseCoin??25);const sb=p.scoreBalance||{};$('#pvpScoreBalanceEnabled').value=sb.enabled===false?'0':'1';$('#pvpScoreEqualRange').value=Number(sb.equalRange??10);$('#pvpWeakerWinMid').value=Number(sb.weakerWinMid??80);$('#pvpWeakerWinHigh').value=Number(sb.weakerWinHigh??60);$('#pvpWeakerWinExtreme').value=Number(sb.weakerWinExtreme??40);$('#pvpStrongerWinMid').value=Number(sb.strongerWinMid??110);$('#pvpStrongerWinHigh').value=Number(sb.strongerWinHigh??125);$('#pvpStrongerWinExtreme').value=Number(sb.strongerWinExtreme??140);$('#pvpStrongerLossMid').value=Number(sb.strongerLossMid??90);$('#pvpStrongerLossHigh').value=Number(sb.strongerLossHigh??75);$('#pvpStrongerLossExtreme').value=Number(sb.strongerLossExtreme??60);$('#pvpWeakerLossMid').value=Number(sb.weakerLossMid??110);$('#pvpWeakerLossHigh').value=Number(sb.weakerLossHigh??125);$('#pvpWeakerLossExtreme').value=Number(sb.weakerLossExtreme??140);$('#pvpMinScoreChange').value=Number(sb.minChange??1);$('#pvpMaxScoreChange').value=Number(sb.maxChange??999);$('#pvpMatchCardRange').value=Number(p.matchCardRange??15);$('#pvpMatchSeasonRange').value=Number(p.matchSeasonRange??300);$('#pvpHistoryLimit').value=Number(p.historyLimit??100);$('#pvpEnergyMax').value=Number(p.energy?.maxEnergy??5);$('#pvpEnergyMinutes').value=Number(p.energy?.rechargeMinutes??30);$('#pvpEnergyEnabled').value=p.energy?.enabled===false?'0':'1';$('#pvpAdminUnlimited').value=p.energy?.adminUnlimited===false?'0':'1';$('#pvpTestUnlimited').value=p.energy?.testUnlimited===false?'0':'1';$('#pvpRewardClaimMode').value=p.rewardClaimMode||'SEASON_END';$('#pvpTierRewardsEnabled').value=p.tierRewardsEnabled===false?'0':'1';$('#pvpRankRewardsEnabled').value=p.rankRewardsEnabled===false?'0':'1';renderTierAdmin()}
function tierAdminMark(t){return `<div class="adminTierMark ${t.aura?'aura':''}" style="--tier-color:${esc(t.color)}"><i>✦</i><b>${esc(t.name)}</b></div>`}
function renderTierAdmin(){const tiers=state.tierData?.settings?.cardScoreTiers||[];$('#tierSettingsRows').innerHTML=tiers.map((t,i)=>`<div class="tierSettingRow" data-i="${i}">${tierAdminMark(t)}<label class="field"><span>티어명</span><input class="tName" value="${esc(t.name)}"></label><label class="field"><span>최소 점수</span><input class="tMin" type="number" min="0" value="${t.min}"></label><label class="field"><span>대표 색상</span><input class="tColor" type="color" value="${esc(t.color)}"></label><label class="field"><span>오라</span><select class="tAura"><option value="1" ${t.aura?'selected':''}>사용</option><option value="0" ${t.aura?'':'selected'}>미사용</option></select></label></div>`).join('');$('#tierAdminRanking').innerHTML=(state.tierData.ranking||[]).slice(0,50).map((r,i)=>`<div class="tr"><span>${i+1}위</span><b>${esc(r.nickname)}</b><span>${Number(r.score).toLocaleString()}점</span></div>`).join('')||'<div class="muted">랭킹 데이터가 없습니다.</div>';renderPvpCms()}
